import type { LocalizedTutorialContent } from '../tutorials-longform-i18n';

// Localized long-form content for one tutorial. Generated from validated
// per-locale translation JSONs; en renders from the Markdown source.
export const entry: Partial<Record<string, LocalizedTutorialContent>> = {
  "zh": {
    title: "告别 Claude Design！这是最强的开源 AI UI 生成器",
    summary: "在 Windows 11 上安装并运行 Open Design——既有简单的原生桌面版，也有通过 WSL（搭配 Node 24 与 pnpm）从源码构建的路线。在本地运行这款开源 AI UI 生成器，无需任何云端订阅。基于 AI Automation 的实操演示整理。",
    bodyHtml: "<p>本指南面向想在自己机器上运行 Open Design 的 Windows 用户——不用云账号，也不用为按月额度发愁。它沿用了 AI Automation 在<a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">他们的 Windows 安装演示</a>中走的路线，并按当前版本重新撰写、更新到最新，让你能逐条命令跟着操作。可以观看上方视频看实时运行，也可以继续往下阅读文字版。</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/01-workspace.webp\" alt=\"在本地运行的 Open Design 工作区。\">\n<em>Open Design 在 Windows 上本地运行：一个开源、agent-native、完全由你掌控的设计工作区。</em></p>\n<h2 id=\"what-is-open-design\">什么是 Open Design？</h2>\n<p>Open Design 是一个开源、本地优先的设计平台——是 Claude Design 和 Figma 的 agent-native 替代方案。它不会把你锁定在某一家模型提供商，而是<strong>运行在你已经在用的编码 agent 之上</strong>：Claude Code、Codex、Cursor、Gemini、Copilot、OpenCode，还有十几种其他选择。它做到的是“自带你的 agent”，而不仅仅是自带你的密钥。</p>\n<p>有几点值得一看：</p>\n<ul>\n<li><strong>开源，采用 Apache-2.0 许可</strong>——可以克隆、自托管、逐行阅读源码。</li>\n<li><strong>本地运行</strong>——你的项目保存在自己机器上的文件夹里，而不是别人的云端。</li>\n<li><strong>可插拔 agent</strong>——支持 21 种以上编码 agent；你来选择由哪个 CLI 驱动生成，输出质量则取决于你选的模型。</li>\n<li><strong>不止于原型</strong>——原型、实时产物、幻灯片、杂志版式、图像生成，乃至视频，全部出自同一个工作区。</li>\n<li><strong>内置设计系统与模板库</strong>，让你不必从一张白纸开始。</li>\n</ul>\n<p>如果你用过 Claude Design，会立刻感到熟悉——Open Design 保留了同样从容的美学，又在此之上叠加了更多能力（以及由你选择的模型）。</p>\n<h2 id=\"before-you-start\">开始之前</h2>\n<p>在 Windows 上安装 Open Design 有三种方式。挑一个适合你的：</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>路线</th><th>适合谁</th><th>前置要求</th></tr></thead><tbody><tr><td><strong>桌面应用（Windows x64）</strong></td><td>大多数 Windows 用户——零配置</td><td>无。下载即可打开。</td></tr><tr><td><strong>从源码运行（WSL）</strong></td><td>想阅读或修改代码的开发者</td><td>WSL2 + Ubuntu、Node <code>~24</code>、pnpm <code>10.33.x</code></td></tr><tr><td><strong>安装进你的 agent</strong></td><td>长居终端的人</td><td>一个现成的编码 agent CLI</td></tr></tbody></table>\n<p>视频用的是 WSL 从源码运行的路线，如果你想常驻在仓库里，这条很棒。但对大多数人来说，<strong>推荐走原生 Windows 桌面版</strong>——有一个 Windows（x64）安装包，不需要 WSL、不需要 Node、也不需要克隆。本指南两条路都会讲到；下面的 WSL 演示是给特别想走源码路线的人准备的。</p>\n<h2 id=\"step-1--set-up-wsl\">第 1 步——配置 WSL</h2>\n<p>如果你只想要桌面应用，直接跳到第 2 步的选项 A。如果你想走源码路线，首先需要在 Windows 内部有一个 Linux 环境。这正是 WSL（适用于 Linux 的 Windows 子系统）所提供的——一个与 Windows 并行运行的真实 Ubuntu shell，无需双系统，也不用照看虚拟机。</p>\n<p><strong>1. 安装 WSL 和 Ubuntu。</strong>打开 PowerShell 并运行 <code>wsl --install</code>——这会启用 WSL2 并默认安装 Ubuntu。如果 Windows 提示重启就重启，然后从开始菜单启动 <strong>Ubuntu</strong>，首次打开时设置你的 Linux 用户名和密码。（已经通过其他工具装好了 Ubuntu？复用它即可——不必重复这一步。）</p>\n<p><strong>2. 更新基础软件包。</strong>在 Ubuntu shell 里刷新软件包索引并安装必要组件：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> update</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#6E7448\"> -y</span><span style=\"color:#6E7448\"> curl</span><span style=\"color:#6E7448\"> git</span></span></code></pre>\n<blockquote>\n<p><strong>视频里的排错提示：</strong>如果后面某一步抛出奇怪的错误，就干净地重启你的 Linux 实例——在 PowerShell 里运行 <code>wsl --shutdown</code>，然后重新打开 Ubuntu。重新启动能解决大多数首次运行的小问题。</p>\n</blockquote>\n<p><strong>3. 安装 Node 24。</strong>源码构建针对的是 Node <code>~24</code>。全新的 Ubuntu 还没有 <code>nvm</code>，所以先安装它，再用它来获取 Node 24：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">curl</span><span style=\"color:#6E7448\"> -o-</span><span style=\"color:#6E7448\"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.3/install.sh</span><span style=\"color:#ED6F5C\"> |</span><span style=\"color:#15140F;font-weight:bold\"> bash</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">source</span><span style=\"color:#6E7448\"> ~/.bashrc</span><span style=\"color:#8B8676;font-style:italic\">            # 把 nvm 加载到当前 shell</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> use</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">node</span><span style=\"color:#6E7448\"> --version</span><span style=\"color:#8B8676;font-style:italic\">              # 应当打印 v24.x</span></span></code></pre>\n<p>Ubuntu 配置好、Node 24 也已启用后，你就可以安装 Open Design 了。</p>\n<h2 id=\"step-2--install-open-design\">第 2 步——安装 Open Design</h2>\n<h3 id=\"option-a--windows-desktop-app-recommended-zero-config\">选项 A——Windows 桌面应用（推荐，零配置）</h3>\n<p>前往 <a href=\"https://open-design.ai/\">open-design.ai</a> 并点击 <strong>Download desktop</strong>。有一个原生 <strong>Windows（x64）</strong>版本（同时也提供 macOS 和 Linux 版）。运行安装程序、打开应用，它会自动检测你 <code>PATH</code> 上已有的每一个编码 agent CLI，然后为你加载内置的 skill 和设计系统。无需 WSL，也无需终端——这是 Windows 上最简单的路线。</p>\n<h3 id=\"option-b--run-from-source-inside-wsl\">选项 B——从源码运行（在 WSL 内）</h3>\n<p>这是 AI Automation 演示的路线。在已启用 Node 24 的 Ubuntu shell 里，克隆仓库并启动 web 运行时：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p><code>corepack enable</code> 让 Corepack 选用仓库中固定的 pnpm 版本（<code>10.33.x</code>），这样你就不必自己安装 pnpm。<code>pnpm install</code> 会拉取依赖并编译原生模块——首次运行可能要花上几分钟，这是预期之内，并非失败。随后 <code>pnpm tools-dev run web</code> 会启动本地守护进程和 web 服务器。</p>\n<p>完成后，命令会<strong>打印一个本地 URL</strong>——复制它并粘贴到你的 <strong>Windows 浏览器</strong>里。WSL 会自动把端口转发到 Windows，所以应用直接就能打开。</p>\n<blockquote>\n<p><strong>重要：</strong>端口是在启动时<strong>动态分配</strong>的——请读取命令实际打印出的地址。不要假设是固定端口；地址在不同机器和不同次运行之间可能不一样。</p>\n</blockquote>\n<h3 id=\"option-c--install-into-your-coding-agent-wsl\">选项 C——安装进你的编码 agent（WSL）</h3>\n<p>更想跳过图形界面、把 Open Design 当作 agent 内部的 MCP 服务器来调用？在 WSL 上<strong>需要先多做一步</strong>。Linux 本身自带 <code>/usr/bin/od</code>（八进制转储工具），它会盖过 Open Design 自己的 <code>od</code>——否则 <code>od mcp install …</code> 会因为找不到 <code>mcp</code>/<code>install</code> 而报“file not found”。添加一个小小的包装脚本，让 <code>od</code> 指向你的克隆，并把它放到 <code>PATH</code> 的最前面：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">mkdir</span><span style=\"color:#6E7448\"> -p</span><span style=\"color:#6E7448\"> ~/.local/bin</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cat</span><span style=\"color:#ED6F5C\"> ></span><span style=\"color:#6E7448\"> ~/.local/bin/od</span><span style=\"color:#ED6F5C\"> &#x3C;&#x3C;</span><span style=\"color:#5A5448\">'EOF'</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">#!/usr/bin/env bash</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">repo=\"$HOME/open-design\"     # Option B 里的 ~/open-design 克隆</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">cd \"$repo\" || exit 127</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">exec corepack pnpm exec od \"$@\"</span></span>\n<span class=\"line\"><span style=\"color:#5A5448\">EOF</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">chmod</span><span style=\"color:#6E7448\"> +x</span><span style=\"color:#6E7448\"> ~/.local/bin/od</span></span>\n<span class=\"line\"><span style=\"color:#ED6F5C\">export</span><span style=\"color:#2A2620\"> PATH</span><span style=\"color:#ED6F5C\">=</span><span style=\"color:#5A5448\">\"</span><span style=\"color:#2A2620\">$HOME</span><span style=\"color:#6E7448\">/.local/bin:</span><span style=\"color:#2A2620\">$PATH</span><span style=\"color:#5A5448\">\"</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">hash</span><span style=\"color:#6E7448\"> -r</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">type</span><span style=\"color:#6E7448\"> -a</span><span style=\"color:#6E7448\"> od</span><span style=\"color:#8B8676;font-style:italic\">                   # 现在应当是 Open Design 的 od 胜出</span></span></code></pre>\n<p>然后把它接入你的 agent：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">od</span><span style=\"color:#6E7448\"> mcp</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> &#x3C;</span><span style=\"color:#6E7448\">agen</span><span style=\"color:#15140F\">t</span><span style=\"color:#ED6F5C\">></span></span>\n<span class=\"line\"><span style=\"color:#8B8676;font-style:italic\"># &#x3C;agent> = claude | codex | cursor | copilot | gemini | opencode | …</span></span></code></pre>\n<p>然后，在 agent 里直接发出请求：<code>Use open-design to generate a landing page with the Airbnb design system</code>。</p>\n<h2 id=\"first-run-connect-your-coding-agent\">首次运行：连接你的编码 agent</h2>\n<p>工作区第一次加载时，Open Design 会扫描你的环境并显示它找到的每一个 CLI。因为 WSL 是一台真正的 Linux 机器，它会识别出装<strong>在 Ubuntu 内部</strong>的 agent——所以驻留在 WSL 里的 Gemini CLI 或其他 agent 会在那里被检测到。如果有什么还没出现，点击 <strong>rescan</strong>。</p>\n<ul>\n<li><strong>选择默认 agent 和模型。</strong>让装好的 CLI 来驱动生成，或者把它指向特定的提供商和模型。正如视频所强调的，更强的模型意味着明显更好的输出，所以当结果很重要时，请选一个有实力的。</li>\n<li><strong>添加媒体提供商（可选）。</strong>要生成图像、视频或音频，就粘贴你自己的 API 密钥——自带密钥，只针对你真正会用到的提供商。</li>\n<li><strong>连接 MCP 服务（可选）。</strong>如果你想让 agent 从其他来源获取内容，就接入相应的连接器。</li>\n<li><strong>设置偏好。</strong>语言、外观、通知——甚至还有一只桌面宠物。这些之后都能改，所以第一次过一遍时保持简单就好。</li>\n</ul>\n<h2 id=\"explore-the-workspace\">探索工作区</h2>\n<p>Open Design 让你的工作保持<strong>以项目为单位</strong>：当你针对某个文件夹运行它时，你创建的设计就保存在那个项目目录里。你的第一个项目列表会是空的——这很正常。</p>\n<p>在一个项目内，你可以构建原型、幻灯片、图像、视频，等等。有两个起点能让空白画布消失：</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/02-design-systems.webp\" alt=\"内置的设计系统库。\">\n<em>设计系统库：挑一个真实的品牌外观——Airbnb、Airtable 等等——Open Design 会把它的 token、颜色和字体带进你的设计。</em></p>\n<ul>\n<li><strong>设计系统</strong>把一个品牌的外观凝练为一份由 token 组成的 <code>DESIGN.md</code>——主色与辅色、字体、间距。预览其中一个，你就能直接在它之上构建，而不必从零定义一套配色。</li>\n<li><strong>模板</strong>涵盖原型、幻灯片，以及图像和视频生成。按类型筛选，fork 任意一个作为起步。</li>\n</ul>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/03-templates.webp\" alt=\"模板库。\">\n<em>模板：原型、幻灯片、图像和视频的起点——按类型筛选，fork 即可开始。</em></p>\n<p>在安装任何东西之前，你可以在网页上浏览完整的库：<a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>。</p>\n<h2 id=\"build-something\">动手做点东西</h2>\n<p>这是 AI Automation 走的流程，按当前版本重新整理：</p>\n<ol>\n<li><strong>挑一个设计系统。</strong>选一个你喜欢的——比如 <strong>Airbnb</strong>——打开它来查看它的 <code>DESIGN.md</code> 和 token。</li>\n<li><strong>把它作为起点导入。</strong>使用 <strong>Share → Download as ZIP</strong>，然后在你的项目里选择 <strong>Import flat design ZIP</strong>。设计就会出现在工作区里，可以在它之上继续构建。</li>\n<li><strong>用提示词描述你想要的改动。</strong>输入一段大白话需求——<em>“能把背景改成深色吗？”</em>——然后发送。agent 会读取设计系统、规划它的工作，并产出该产物的一个新版本。</li>\n<li><strong>自由迭代。</strong>换字体、添加或移除 logo、上传你自己的素材并让它们被放到合适的位置。每条提示都会产出一个新方案，留下或舍弃由你。</li>\n<li><strong>满意了就导出。</strong>点 <strong>Share</strong> 并把结果下载为 ZIP。</li>\n</ol>\n<p>输出是一份真实、可编辑、由你所连接模型驱动的设计——所以一个有实力的 agent 会直接反映在你拿回的成果里。</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">用得更顺手的几点提示</h2>\n<ul>\n<li><strong>选一个强模型。</strong>输出质量取决于你连接的 agent——免费模型足以学会整个流程，但真要做正事，一个有实力的模型值得投入。</li>\n<li><strong>每次都读打印出来的 URL。</strong>本地地址是动态的；复制 <code>tools-dev</code> 打印出的内容，别复用旧链接。</li>\n<li><strong>把你的 agent 装在 Open Design 会查找的地方。</strong>在 WSL 里从源码运行？就把你的 CLI 装在 Ubuntu 内部，这样工作区才能检测到它们；桌面应用读取的是你 Windows 的 <code>PATH</code>。</li>\n<li><strong>不需要先有设计系统才能开始。</strong>可以从内置的某一个起步、导入一个 ZIP，或让 Open Design 推断默认值。你的设计会留在项目文件夹里，所以通过针对正确的目录运行来组织你的工作。</li>\n</ul>\n<h2 id=\"faq\">常见问题</h2>\n<p><strong>Open Design 免费吗？</strong>\n是的——它是采用 Apache-2.0 许可的开源软件。你可以免费在本地运行；你只需要为所连接的 agent 和媒体提供商的模型/API 用量付费。</p>\n<p><strong>我该用 WSL 还是 Windows 桌面应用？</strong>\n对大多数人来说，原生 Windows（x64）桌面版更简单——不用 WSL、不用 Node、不用克隆。当你特别想阅读或修改代码时，再用 WSL 从源码运行的路线。请注意，WSL2 是主要受支持的路线，而 Windows 原生版属于尽力支持；如果一条路遇到阻碍，可以试试另一条。</p>\n<p><strong>它支持哪些编码 agent？</strong>\n21 种以上的 agent，包括 Claude Code、Codex、Cursor、Gemini、GitHub Copilot 和 OpenCode。Open Design 会检测你机器上已经安装的 CLI——源码路线下在 WSL 内部检测，桌面应用则在你的 Windows <code>PATH</code> 上检测。</p>\n<p><strong>它和 Claude Design 有什么不同？</strong>\n同样熟悉的体验，但开源、本地优先、可插拔 agent——所以你不会被锁定在某一个模型上，也不会去消耗一个固定的额度池。它还超越了原型，提供幻灯片、杂志版式、图像生成和视频。</p>\n<hr>\n<p><em>这份文字指南基于 AI Automation 的 Windows 安装演示。请观看上方的完整视频，并<a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">订阅 AI Automation</a> 以获取更多 AI 工具的实操视频。</em></p>",
  },
  "ja": {
    title: "さらばClaude Design！これが最高のオープンソースAI UIジェネレーター",
    summary: "Windows 11でOpen Designをインストールして実行する——シンプルなネイティブのデスクトップ版に加え、Node 24とpnpmを使いWSL経由でソースからビルドする方法も解説します。オープンソースのAI UIジェネレーターをクラウドのサブスクリプションなしでローカルに動かしましょう。AI Automationのチュートリアルを基にしています。",
    bodyHtml: "<p>このガイドは、自分のマシンでOpen Designを動かしたいWindowsユーザーのためのものです——クラウドアカウントも、使い切るための月額クレジットも不要です。AI Automationが<a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">Windowsインストールのチュートリアル</a>で示している手順を踏襲しつつ、コマンドを1つずつ追えるよう最新リリースに合わせて書き直しました。実際の操作は上の動画で確認するか、このままテキスト版を読み進めてください。</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/01-workspace.webp\" alt=\"ローカルで動作するOpen Designのワークスペース。\">\n<em>WindowsでローカルにOpen Designを実行：完全に自分で管理できる、オープンソースかつエージェントネイティブなデザインワークスペース。</em></p>\n<h2 id=\"what-is-open-design\">Open Designとは？</h2>\n<p>Open Designは、オープンソースでローカルファーストのデザインプラットフォームです——Claude DesignやFigmaに代わるエージェントネイティブな選択肢です。1つのモデルプロバイダーに縛られるのではなく、<strong>すでに使っているコーディングエージェントの上で</strong>動作します：Claude Code、Codex、Cursor、Gemini、Copilot、OpenCode、そのほか多数。単に鍵を持ち込むだけでなく、“bring your own agent”という発想です。</p>\n<p>注目に値する点をいくつか挙げます：</p>\n<ul>\n<li><strong>オープンソース、Apache-2.0</strong> — クローンして、セルフホストし、すべての行を読めます。</li>\n<li><strong>ローカルで動作</strong> — プロジェクトは他人のクラウドではなく、自分のマシンの自分のフォルダーに保存されます。</li>\n<li><strong>エージェントを差し替え可能</strong> — 21以上のコーディングエージェントに対応。どのCLIで生成を駆動するかを選べ、出力の品質は選んだモデルに連動します。</li>\n<li><strong>プロトタイプにとどまらない</strong> — プロトタイプ、ライブアーティファクト、スライドデッキ、マガジンレイアウト、画像生成、さらには動画まで、すべて1つのワークスペースから。</li>\n<li><strong>デザインシステムとテンプレートの組み込みライブラリ</strong>があるので、真っ白なキャンバスから始める必要はありません。</li>\n</ul>\n<p>Claude Designを使ったことがあれば、すぐに馴染めるはずです——Open Designは同じ落ち着いた美しさをそのままに、その上に機能（とモデルの選択肢）を加えています。</p>\n<h2 id=\"before-you-start\">始める前に</h2>\n<p>WindowsにOpen Designをインストールする方法は3つあります。自分に合うものを選んでください：</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>経路</th><th>向いている人</th><th>必要なもの</th></tr></thead><tbody><tr><td><strong>デスクトップアプリ（Windows x64）</strong></td><td>ほとんどのWindowsユーザー — 設定不要</td><td>なし。ダウンロードして開くだけ。</td></tr><tr><td><strong>ソースから実行（WSL）</strong></td><td>コードを読んだり変更したい開発者</td><td>WSL2 + Ubuntu、Node <code>~24</code>、pnpm <code>10.33.x</code></td></tr><tr><td><strong>エージェントに組み込む</strong></td><td>ターミナルで作業する人</td><td>既存のコーディングエージェントのCLI</td></tr></tbody></table>\n<p>動画ではWSLでソースから実行する経路を使っています。リポジトリの中で作業したいなら最適です。ただしほとんどの人には<strong>ネイティブのWindowsデスクトップ版が推奨ルート</strong>です——WSLもNodeもクローンも不要なWindows（x64）インストーラーがあります。本ガイドは両方を扱いますが、以下のWSLチュートリアルは、あえてソース経路を選びたい場合向けです。</p>\n<h2 id=\"step-1--set-up-wsl\">ステップ1 — WSLをセットアップする</h2>\n<p>デスクトップアプリだけが目的なら、ステップ2のオプションAまで読み飛ばしてください。ソースから実行したい場合は、まずWindows内にLinux環境が必要です。それを提供してくれるのがWSL（Windows Subsystem for Linux）です——デュアルブートも、世話の焼ける仮想マシンもなく、Windowsと並んで動く本物のUbuntuシェルが手に入ります。</p>\n<p><strong>1. WSLとUbuntuをインストールする。</strong> PowerShellを開いて<code>wsl --install</code>を実行します——これでWSL2が有効になり、既定でUbuntuがインストールされます。Windowsが求めたら再起動し、スタートメニューから<strong>Ubuntu</strong>を起動して、初回起動時にLinuxのユーザー名とパスワードを設定します。（別のツールで導入したUbuntuがすでにありますか？それを再利用すればよく、これを繰り返す必要はありません。）</p>\n<p><strong>2. ベースパッケージを更新する。</strong> Ubuntuシェル内で、パッケージインデックスを更新し、必須ツールをインストールします：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> update</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#6E7448\"> -y</span><span style=\"color:#6E7448\"> curl</span><span style=\"color:#6E7448\"> git</span></span></code></pre>\n<blockquote>\n<p><strong>動画からのトラブルシューティングのヒント：</strong> 後の手順で不可解なエラーが出たら、Linuxインスタンスをきれいに再起動してください——PowerShellから<code>wsl --shutdown</code>を実行し、Ubuntuを開き直します。新しく起動し直すことで、初回特有のトラブルのほとんどが解消します。</p>\n</blockquote>\n<p><strong>3. Node 24をインストールする。</strong> ソースからのビルドはNode <code>~24</code>を対象としています。まっさらなUbuntuにはまだ<code>nvm</code>がないので、先にそれをインストールし、それを使ってNode 24を入れます：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">curl</span><span style=\"color:#6E7448\"> -o-</span><span style=\"color:#6E7448\"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.3/install.sh</span><span style=\"color:#ED6F5C\"> |</span><span style=\"color:#15140F;font-weight:bold\"> bash</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">source</span><span style=\"color:#6E7448\"> ~/.bashrc</span><span style=\"color:#8B8676;font-style:italic\">            # load nvm into the current shell</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> use</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">node</span><span style=\"color:#6E7448\"> --version</span><span style=\"color:#8B8676;font-style:italic\">              # should print v24.x</span></span></code></pre>\n<p>UbuntuのセットアップとNode 24の有効化が済んだら、Open Designをインストールする準備は完了です。</p>\n<h2 id=\"step-2--install-open-design\">ステップ2 — Open Designをインストールする</h2>\n<h3 id=\"option-a--windows-desktop-app-recommended-zero-config\">オプションA — Windowsデスクトップアプリ（推奨、設定不要）</h3>\n<p><a href=\"https://open-design.ai/\">open-design.ai</a> にアクセスして<strong>Download desktop</strong>をクリックします。macOSやLinux版と並んでネイティブの<strong>Windows (x64)</strong>ビルドがあります。インストーラーを実行してアプリを開くと、<code>PATH</code>上にあるすべてのコーディングエージェントのCLIを自動検出し、組み込みのスキルとデザインシステムを読み込んでくれます。WSLもターミナルも不要——これがWindowsで最もシンプルな経路です。</p>\n<h3 id=\"option-b--run-from-source-inside-wsl\">オプションB — ソースから実行する（WSL内）</h3>\n<p>これはAI Automationが実演している経路です。Node 24を有効にしたUbuntuシェル内で、リポジトリをクローンし、Webランタイムを起動します：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p><code>corepack enable</code>を実行すると、Corepackがリポジトリで固定されたpnpmのバージョン（<code>10.33.x</code>）を選ぶので、自分でpnpmをインストールする必要はありません。<code>pnpm install</code>は依存関係を取得し、ネイティブな部分をコンパイルします——初回は数分かかることがありますが、これは想定どおりで失敗ではありません。続いて<code>pnpm tools-dev run web</code>がローカルのデーモンとWebサーバーを起動します。</p>\n<p>完了すると、コマンドが<strong>ローカルのURLを表示します</strong>——それをコピーして<strong>Windowsのブラウザー</strong>に貼り付けてください。WSLがポートを自動的にWindowsへ転送するので、アプリはそのまま開きます。</p>\n<blockquote>\n<p><strong>重要：</strong> ポートは起動時に<strong>動的に割り当てられます</strong>——コマンドが実際に表示するアドレスを読み取ってください。固定ポートだと思い込まないこと。アドレスはマシンごとに、また実行のたびに異なる場合があります。</p>\n</blockquote>\n<h3 id=\"option-c--install-into-your-coding-agent-wsl\">オプションC — コーディングエージェントに組み込む（WSL）</h3>\n<p>GUIを使わず、Open Designをエージェント内のMCPサーバーとして呼び出したいですか？WSLでは<strong>最初に1つ余分な手順</strong>があります。Linuxにはもともと<code>/usr/bin/od</code>（8進ダンプツール）が同梱されており、これがOpen Design自身の<code>od</code>を覆い隠してしまいます——そのため<code>od mcp install …</code>はそのままだと<code>mcp</code>／<code>install</code>が“file not found”になって失敗します。<code>od</code>をクローン先に向ける小さなラッパーを追加し、<code>PATH</code>の先頭に置きましょう：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">mkdir</span><span style=\"color:#6E7448\"> -p</span><span style=\"color:#6E7448\"> ~/.local/bin</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cat</span><span style=\"color:#ED6F5C\"> ></span><span style=\"color:#6E7448\"> ~/.local/bin/od</span><span style=\"color:#ED6F5C\"> &#x3C;&#x3C;</span><span style=\"color:#5A5448\">'EOF'</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">#!/usr/bin/env bash</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">repo=\"$HOME/open-design\"     # the ~/open-design clone from Option B</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">cd \"$repo\" || exit 127</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">exec corepack pnpm exec od \"$@\"</span></span>\n<span class=\"line\"><span style=\"color:#5A5448\">EOF</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">chmod</span><span style=\"color:#6E7448\"> +x</span><span style=\"color:#6E7448\"> ~/.local/bin/od</span></span>\n<span class=\"line\"><span style=\"color:#ED6F5C\">export</span><span style=\"color:#2A2620\"> PATH</span><span style=\"color:#ED6F5C\">=</span><span style=\"color:#5A5448\">\"</span><span style=\"color:#2A2620\">$HOME</span><span style=\"color:#6E7448\">/.local/bin:</span><span style=\"color:#2A2620\">$PATH</span><span style=\"color:#5A5448\">\"</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">hash</span><span style=\"color:#6E7448\"> -r</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">type</span><span style=\"color:#6E7448\"> -a</span><span style=\"color:#6E7448\"> od</span><span style=\"color:#8B8676;font-style:italic\">                   # Open Design's od should now win</span></span></code></pre>\n<p>次に、これをエージェントに接続します：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">od</span><span style=\"color:#6E7448\"> mcp</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> &#x3C;</span><span style=\"color:#6E7448\">agen</span><span style=\"color:#15140F\">t</span><span style=\"color:#ED6F5C\">></span></span>\n<span class=\"line\"><span style=\"color:#8B8676;font-style:italic\"># &#x3C;agent> = claude | codex | cursor | copilot | gemini | opencode | …</span></span></code></pre>\n<p>あとはエージェント内でこう頼むだけです：<code>Use open-design to generate a landing page with the Airbnb design system</code>.</p>\n<h2 id=\"first-run-connect-your-coding-agent\">初回起動：コーディングエージェントを接続する</h2>\n<p>ワークスペースが初めて読み込まれると、Open Designは環境をスキャンし、見つかったすべてのCLIを表示します。WSLは本物のLinux環境なので、<strong>Ubuntu内</strong>にインストールされたエージェントも拾います——つまりWSL内にあるGemini CLIなどのエージェントもそこで検出されます。まだ表示されないものがあれば、<strong>rescan</strong>（再スキャン）をクリックしてください。</p>\n<ul>\n<li><strong>既定のエージェントとモデルを選ぶ。</strong> インストール済みのCLIに生成を任せるか、特定のプロバイダーとモデルを指定します。動画でも強調されているとおり、強力なモデルほど出力が目に見えて良くなるので、結果が重要なときは性能の高いものを選びましょう。</li>\n<li><strong>メディアプロバイダーを追加する（任意）。</strong> 画像・動画・音声を生成するには、自分のAPIキーを貼り付けます——bring-your-own-keyで、実際に使うプロバイダーの分だけ。</li>\n<li><strong>MCPサービスを接続する（任意）。</strong> エージェントに他のソースから取得させたい場合は、コネクターを接続します。</li>\n<li><strong>設定を整える。</strong> 言語、外観、通知——デスクトップペットまで。これらは後からいつでも変更できるので、最初はシンプルに済ませましょう。</li>\n</ul>\n<h2 id=\"explore-the-workspace\">ワークスペースを見て回る</h2>\n<p>Open Designは作業を<strong>プロジェクト単位</strong>で管理します：あるフォルダーに対して実行すると、作成したデザインはそのプロジェクトのディレクトリ内に保存されます。最初のプロジェクト一覧は空ですが、それで正常です。</p>\n<p>プロジェクト内では、プロトタイプ、スライドデッキ、画像、動画などを作れます。真っ白なキャンバスを解消する出発点が2つあります：</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/02-design-systems.webp\" alt=\"組み込みのデザインシステムライブラリ。\">\n<em>デザインシステムライブラリ：Airbnb、Airtableをはじめ多数の中から実在するブランドのルックを選べば、Open Designがそのトークン、カラー、タイポグラフィをあなたのデザインに取り込みます。</em></p>\n<ul>\n<li><strong>デザインシステム</strong>は、ブランドのルックをトークンの<code>DESIGN.md</code>として捉えます——プライマリ／セカンダリカラー、タイポグラフィ、スペーシングなど。プレビューすれば、パレットを一から定義する代わりに、その上に直接構築できます。</li>\n<li><strong>テンプレート</strong>は、プロトタイプ、スライド、そして画像・動画の生成をカバーします。種類で絞り込み、どれでもフォークして手早く始められます。</li>\n</ul>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/03-templates.webp\" alt=\"テンプレートライブラリ。\">\n<em>テンプレート：プロトタイプ、スライド、画像、動画の出発点——種類で絞り込み、フォークして始めましょう。</em></p>\n<p>何かをインストールする前に、<a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> でライブラリ全体をWeb上で閲覧できます。</p>\n<h2 id=\"build-something\">何かを作ってみる</h2>\n<p>AI Automationが実演している流れを、最新リリースに合わせて書き直したものです：</p>\n<ol>\n<li><strong>デザインシステムを選ぶ。</strong> 気に入ったものを——たとえば<strong>Airbnb</strong>を——選び、開いてその<code>DESIGN.md</code>とトークンを確認します。</li>\n<li><strong>出発点として読み込む。</strong> <strong>Share → Download as ZIP</strong>を使い、続いてプロジェクトで<strong>Import flat design ZIP</strong>を選びます。デザインがワークスペースに現れ、その上に構築する準備が整います。</li>\n<li><strong>欲しい変更をプロンプトで伝える。</strong> 平易な言葉で指示を入力します——<em>“背景を暗くできますか？”</em>——そして送信します。エージェントはデザインシステムを読み取り、作業を計画し、アーティファクトの新しいバージョンを生成します。</li>\n<li><strong>自由に反復する。</strong> フォントを変えたり、ロゴを追加・削除したり、自分のアセットをアップロードして適切な場所に配置させたりできます。各プロンプトが新しい案を生み出すので、採用するか破棄するか選べます。</li>\n<li><strong>満足したらエクスポートする。</strong> <strong>Share</strong>を押して、結果をZIPとしてダウンロードします。</li>\n</ol>\n<p>出力は、接続したモデルによって駆動される、本物の編集可能なデザインです——だからこそ高性能なエージェントは、得られる結果に直接報いてくれます。</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">もっと活用するためのヒント</h2>\n<ul>\n<li><strong>強力なモデルを選ぶ。</strong> 出力の品質は接続したエージェントに連動します——流れを学ぶには無料モデルでも十分ですが、本番の仕事には高性能なものを選ぶ価値があります。</li>\n<li><strong>毎回、表示されたURLを読む。</strong> ローカルのアドレスは動的です。古いリンクを使い回すのではなく、<code>tools-dev</code>が表示するものをコピーしてください。</li>\n<li><strong>Open Designが探す場所にエージェントを入れる。</strong> WSLでソースから実行していますか？ワークスペースが検出できるよう、CLIはUbuntu内にインストールしましょう。デスクトップアプリはWindowsの<code>PATH</code>を読み取ります。</li>\n<li><strong>始めるのにデザインシステムは不要。</strong> 組み込みのものから始めても、ZIPを読み込んでも、Open Designに既定値を推測させてもかまいません。デザインはプロジェクトフォルダーとともに残るので、適切なディレクトリに対して実行することで作業を整理しましょう。</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Open Designは無料ですか？</strong>\nはい——Apache-2.0ライセンスのオープンソースです。ローカルでは無料で実行でき、料金が発生するのは、接続したエージェントとメディアプロバイダーのモデル／API利用分だけです。</p>\n<p><strong>WSLとWindowsデスクトップアプリのどちらを使うべき？</strong>\nほとんどの人にはネイティブのWindows (x64) デスクトップ版の方がシンプルです——WSLもNodeもクローンも不要。コードを読んだり変更したい場合に限ってWSLのソース経路を使ってください。なお、WSL2は主にサポートされる経路で、Windowsネイティブはベストエフォートです。片方でつまずいたら、もう片方を試してみてください。</p>\n<p><strong>どのコーディングエージェントに対応していますか？</strong>\nClaude Code、Codex、Cursor、Gemini、GitHub Copilot、OpenCodeを含む21以上のエージェントです。Open Designは、マシンにすでにインストールされているCLIを検出します——ソース経路ならWSL内、デスクトップアプリならWindowsの<code>PATH</code>上です。</p>\n<p><strong>Claude Designとどう違うのですか？</strong>\n馴染みのある感覚は同じですが、オープンソースでローカルファースト、そしてエージェントを差し替え可能です——だから1つのモデルに縛られたり、決まったクレジット枠を使い切ったりすることはありません。さらにスライドデッキ、マガジンレイアウト、画像生成、動画など、プロトタイプの先まで広がります。</p>\n<hr>\n<p><em>この記事のガイドは、AI AutomationのWindowsインストールのチュートリアルを基にしています。上のフル動画をご覧いただき、<a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">AI Automationを購読してください</a>——実践的なAIツールの動画をもっと見られます。</em></p>",
  },
  "ko": {
    title: "Claude Design여 안녕! 최고의 오픈소스 AI UI 생성기가 여기 있다",
    summary: "Windows 11에서 Open Design을 설치하고 실행하세요 — 간편한 네이티브 데스크톱 빌드는 물론, Node 24와 pnpm을 사용해 WSL을 거쳐 소스로 빌드하는 방법까지. 오픈소스 AI UI 생성기를 클라우드 구독 없이 로컬에서 실행하세요. AI Automation의 실습 영상을 바탕으로 합니다.",
    bodyHtml: "<p>이 가이드는 자신의 컴퓨터에서 Open Design을 실행하고 싶은 Windows 사용자를 위한 것입니다 — 클라우드 계정도, 소진해야 할 월간 크레딧도 필요 없습니다. AI Automation이 <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">그들의 Windows 설치 실습 영상</a>에서 따라가는 경로를 그대로 따르되, 명령어 하나하나를 따라 할 수 있도록 최신 릴리스에 맞게 다시 쓰고 업데이트했습니다. 실제 실행 과정은 위 영상을 보고, 글로 된 버전은 아래에서 읽어 보세요.</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/01-workspace.webp\" alt=\"로컬에서 실행 중인 Open Design 작업 공간.\">\n<em>Windows에서 로컬로 실행되는 Open Design: 완전히 직접 제어하는 오픈소스 에이전트 네이티브 디자인 작업 공간입니다.</em></p>\n<h2 id=\"what-is-open-design\">Open Design이란?</h2>\n<p>Open Design은 오픈소스이자 로컬 우선 디자인 플랫폼으로, Claude Design과 Figma에 대한 에이전트 네이티브 대안입니다. 하나의 모델 공급자에 묶이는 대신, <strong>이미 사용 중인 코딩 에이전트 위에서</strong> 실행됩니다: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode 등 십수 가지입니다. 단순히 자신의 키를 가져오는 것을 넘어 “자신의 에이전트를 가져오는” 방식입니다.</p>\n<p>주목할 만한 점 몇 가지:</p>\n<ul>\n<li><strong>오픈소스, Apache-2.0</strong> — 복제하고, 직접 호스팅하고, 모든 코드를 읽어 보세요.</li>\n<li><strong>로컬에서 실행</strong> — 프로젝트가 다른 누군가의 클라우드가 아니라 내 컴퓨터의 내 폴더 안에 저장됩니다.</li>\n<li><strong>에이전트 플러그인 방식</strong> — 21개 이상의 코딩 에이전트가 지원됩니다. 어떤 CLI가 생성을 구동할지 직접 고르며, 출력 품질은 선택한 모델을 따라갑니다.</li>\n<li><strong>프로토타입 그 이상</strong> — 프로토타입, 라이브 아티팩트, 슬라이드 덱, 매거진 레이아웃, 이미지 생성, 심지어 영상까지 모두 하나의 작업 공간에서.</li>\n<li><strong>디자인 시스템과 템플릿 내장 라이브러리</strong>로, 빈 캔버스에서 시작하지 않아도 됩니다.</li>\n</ul>\n<p>Claude Design을 사용해 본 적이 있다면 그 느낌이 즉시 익숙할 것입니다 — Open Design은 동일하게 차분한 미감을 유지하면서, 그 위에 기능(그리고 원하는 모델 선택권)을 더합니다.</p>\n<h2 id=\"before-you-start\">시작하기 전에</h2>\n<p>Windows에서 Open Design을 설치하는 방법은 세 가지입니다. 자신에게 맞는 것을 고르세요:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>경로</th><th>적합한 대상</th><th>요구 사항</th></tr></thead><tbody><tr><td><strong>데스크톱 앱 (Windows x64)</strong></td><td>대부분의 Windows 사용자 — 설정 불필요</td><td>없음. 내려받아 열기만 하면 됩니다.</td></tr><tr><td><strong>소스에서 실행 (WSL)</strong></td><td>코드를 읽거나 수정하고 싶은 개발자</td><td>WSL2 + Ubuntu, Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>에이전트에 설치</strong></td><td>터미널에서 사는 사람</td><td>이미 설치된 코딩 에이전트 CLI</td></tr></tbody></table>\n<p>이 영상은 WSL 소스 빌드 경로를 사용하는데, 저장소 안에서 작업하고 싶다면 아주 좋은 방법입니다. 하지만 대부분의 사람에게는 <strong>네이티브 Windows 데스크톱 빌드가 권장 경로</strong>입니다 — WSL도, Node도, 복제도 필요 없는 Windows (x64) 설치 프로그램이 있습니다. 이 가이드는 두 가지를 모두 다룹니다. 아래 WSL 실습은 특별히 소스 경로를 원할 때를 위한 것입니다.</p>\n<h2 id=\"step-1--set-up-wsl\">1단계 — WSL 설정</h2>\n<p>데스크톱 앱만 원한다면 2단계의 옵션 A로 건너뛰세요. 소스 빌드 경로를 원한다면 먼저 Windows 안에 Linux 환경이 필요합니다. 바로 그것을 WSL(Windows Subsystem for Linux)이 제공합니다 — 듀얼 부팅도, 돌봐야 할 가상 머신도 없이 Windows와 나란히 실행되는 진짜 Ubuntu 셸입니다.</p>\n<p><strong>1. WSL과 Ubuntu를 설치합니다.</strong> PowerShell을 열고 <code>wsl --install</code>을 실행하세요 — 이 명령은 WSL2를 활성화하고 기본으로 Ubuntu를 설치합니다. Windows가 요청하면 재부팅한 뒤, 시작 메뉴에서 <strong>Ubuntu</strong>를 실행하고 처음 열릴 때 Linux 사용자 이름과 비밀번호를 설정하세요. (다른 도구에서 이미 Ubuntu를 설치했나요? 그대로 재사용하면 됩니다 — 다시 할 필요 없습니다.)</p>\n<p><strong>2. 기본 패키지를 업데이트합니다.</strong> Ubuntu 셸 안에서 패키지 인덱스를 새로 고치고 필수 패키지를 설치하세요:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> update</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#6E7448\"> -y</span><span style=\"color:#6E7448\"> curl</span><span style=\"color:#6E7448\"> git</span></span></code></pre>\n<blockquote>\n<p><strong>영상에서 알려 주는 문제 해결 팁:</strong> 이후 단계에서 이상한 오류가 발생하면 Linux 인스턴스를 깔끔하게 다시 시작하세요 — PowerShell에서 <code>wsl --shutdown</code>을 실행한 다음 Ubuntu를 다시 여세요. 새로 시작하면 첫 실행 시의 자잘한 문제 대부분이 해결됩니다.</p>\n</blockquote>\n<p><strong>3. Node 24를 설치합니다.</strong> 소스 빌드는 Node <code>~24</code>를 대상으로 합니다. 깨끗한 Ubuntu에는 아직 <code>nvm</code>이 없으므로, 먼저 설치한 뒤 그것으로 Node 24를 받으세요:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">curl</span><span style=\"color:#6E7448\"> -o-</span><span style=\"color:#6E7448\"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.3/install.sh</span><span style=\"color:#ED6F5C\"> |</span><span style=\"color:#15140F;font-weight:bold\"> bash</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">source</span><span style=\"color:#6E7448\"> ~/.bashrc</span><span style=\"color:#8B8676;font-style:italic\">            # 현재 셸에 nvm을 로드</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> use</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">node</span><span style=\"color:#6E7448\"> --version</span><span style=\"color:#8B8676;font-style:italic\">              # v24.x가 출력되어야 함</span></span></code></pre>\n<p>Ubuntu가 설정되고 Node 24가 활성화되면 Open Design을 설치할 준비가 끝난 것입니다.</p>\n<h2 id=\"step-2--install-open-design\">2단계 — Open Design 설치</h2>\n<h3 id=\"option-a--windows-desktop-app-recommended-zero-config\">옵션 A — Windows 데스크톱 앱 (권장, 설정 불필요)</h3>\n<p><a href=\"https://open-design.ai/\">open-design.ai</a>로 이동해 <strong>Download desktop</strong>을 클릭하세요. 네이티브 <strong>Windows (x64)</strong> 빌드가 있습니다(macOS와 Linux와 함께). 설치 프로그램을 실행하고 앱을 연 다음, 앱이 이미 <code>PATH</code>에 있는 모든 코딩 에이전트 CLI를 자동으로 감지하고 내장 스킬과 디자인 시스템을 불러옵니다. WSL도, 터미널도 필요 없습니다 — Windows에서 가장 간단한 경로입니다.</p>\n<h3 id=\"option-b--run-from-source-inside-wsl\">옵션 B — 소스에서 실행 (WSL 내부)</h3>\n<p>AI Automation이 시연하는 경로입니다. Node 24가 활성화된 Ubuntu 셸 안에서 저장소를 복제하고 웹 런타임을 시작하세요:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p><code>corepack enable</code>는 Corepack이 저장소에 고정된 pnpm 버전(<code>10.33.x</code>)을 선택하도록 해 주므로, pnpm을 직접 설치하지 않아도 됩니다. <code>pnpm install</code>은 의존성을 받아 오고 네이티브 구성 요소를 컴파일합니다 — 첫 실행에서는 몇 분이 걸릴 수 있는데, 이는 예상된 동작이며 실패가 아닙니다. 이어서 <code>pnpm tools-dev run web</code>이 로컬 데몬과 웹 서버를 부팅합니다.</p>\n<p>완료되면 명령이 <strong>로컬 URL을 출력</strong>합니다 — 복사해서 <strong>Windows 브라우저</strong>에 붙여 넣으세요. WSL이 포트를 Windows로 자동 전달하므로 앱이 그대로 열립니다.</p>\n<blockquote>\n<p><strong>중요:</strong> 포트는 실행 시 <strong>동적으로 할당</strong>됩니다 — 명령이 실제로 출력하는 주소를 읽으세요. 고정된 포트라고 가정하지 마세요. 주소는 컴퓨터마다, 실행마다 다를 수 있습니다.</p>\n</blockquote>\n<h3 id=\"option-c--install-into-your-coding-agent-wsl\">옵션 C — 코딩 에이전트에 설치 (WSL)</h3>\n<p>GUI를 건너뛰고 에이전트 안에서 Open Design을 MCP 서버로 호출하고 싶나요? WSL에서는 <strong>먼저 한 가지 추가 단계</strong>가 있습니다. Linux에는 이미 <code>/usr/bin/od</code>(octal-dump 도구)가 들어 있어 Open Design 자체의 <code>od</code>를 가립니다 — 그래서 그대로 두면 <code>od mcp install …</code>이 <code>mcp</code>/<code>install</code>에 대해 “file not found” 오류로 실패할 수 있습니다. <code>od</code>가 여러분의 복제본을 가리키도록 하는 작은 래퍼를 추가하고 <code>PATH</code>의 맨 앞에 두세요:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">mkdir</span><span style=\"color:#6E7448\"> -p</span><span style=\"color:#6E7448\"> ~/.local/bin</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cat</span><span style=\"color:#ED6F5C\"> ></span><span style=\"color:#6E7448\"> ~/.local/bin/od</span><span style=\"color:#ED6F5C\"> &#x3C;&#x3C;</span><span style=\"color:#5A5448\">'EOF'</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">#!/usr/bin/env bash</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">repo=\"$HOME/open-design\"     # Option B의 ~/open-design 복제본</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">cd \"$repo\" || exit 127</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">exec corepack pnpm exec od \"$@\"</span></span>\n<span class=\"line\"><span style=\"color:#5A5448\">EOF</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">chmod</span><span style=\"color:#6E7448\"> +x</span><span style=\"color:#6E7448\"> ~/.local/bin/od</span></span>\n<span class=\"line\"><span style=\"color:#ED6F5C\">export</span><span style=\"color:#2A2620\"> PATH</span><span style=\"color:#ED6F5C\">=</span><span style=\"color:#5A5448\">\"</span><span style=\"color:#2A2620\">$HOME</span><span style=\"color:#6E7448\">/.local/bin:</span><span style=\"color:#2A2620\">$PATH</span><span style=\"color:#5A5448\">\"</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">hash</span><span style=\"color:#6E7448\"> -r</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">type</span><span style=\"color:#6E7448\"> -a</span><span style=\"color:#6E7448\"> od</span><span style=\"color:#8B8676;font-style:italic\">                   # 이제 Open Design의 od가 우선되어야 함</span></span></code></pre>\n<p>그런 다음 에이전트에 연결하세요:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">od</span><span style=\"color:#6E7448\"> mcp</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> &#x3C;</span><span style=\"color:#6E7448\">agen</span><span style=\"color:#15140F\">t</span><span style=\"color:#ED6F5C\">></span></span>\n<span class=\"line\"><span style=\"color:#8B8676;font-style:italic\"># &#x3C;agent> = claude | codex | cursor | copilot | gemini | opencode | …</span></span></code></pre>\n<p>그런 다음 에이전트 안에서 이렇게 요청하기만 하면 됩니다: <code>Use open-design to generate a landing page with the Airbnb design system</code>.</p>\n<h2 id=\"first-run-connect-your-coding-agent\">첫 실행: 코딩 에이전트 연결</h2>\n<p>작업 공간이 처음 로드될 때, Open Design은 환경을 스캔해 찾아낸 모든 CLI를 보여 줍니다. WSL은 진짜 Linux 박스이므로 <strong>Ubuntu 내부에</strong> 설치된 에이전트도 인식합니다 — 그래서 WSL에 들어 있는 Gemini CLI나 다른 에이전트가 거기서 감지됩니다. 아직 표시되지 않는 항목이 있으면 <strong>rescan</strong>을 클릭하세요.</p>\n<ul>\n<li><strong>기본 에이전트와 모델을 선택하세요.</strong> 설치된 CLI가 생성을 구동하게 하거나, 특정 공급자와 모델을 지정하세요. 영상에서 강조하듯 더 강력한 모델일수록 출력이 눈에 띄게 좋아지므로, 결과가 중요할 때는 유능한 모델을 선택하세요.</li>\n<li><strong>미디어 공급자를 추가하세요 (선택).</strong> 이미지, 영상, 오디오를 생성하려면 자신의 API 키를 붙여 넣으세요 — 실제로 사용하는 공급자에 한해, 자신의 키를 가져오는 방식입니다.</li>\n<li><strong>MCP 서비스를 연결하세요 (선택).</strong> 에이전트가 다른 소스에서 가져오기를 원한다면 커넥터를 연결하세요.</li>\n<li><strong>환경 설정을 지정하세요.</strong> 언어, 외관, 알림 — 심지어 데스크톱 펫까지. 이 모든 것은 나중에 바꿀 수 있으니 처음에는 단순하게 두세요.</li>\n</ul>\n<h2 id=\"explore-the-workspace\">작업 공간 둘러보기</h2>\n<p>Open Design은 작업을 <strong>프로젝트 단위로</strong> 유지합니다: 특정 폴더를 대상으로 실행하면, 만든 디자인이 그 프로젝트 디렉터리 안에 저장됩니다. 처음에는 프로젝트 목록이 비어 있습니다 — 정상입니다.</p>\n<p>프로젝트 안에서는 프로토타입, 슬라이드 덱, 이미지, 영상 등을 만들 수 있습니다. 빈 캔버스를 사라지게 하는 두 가지 시작점이 있습니다:</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/02-design-systems.webp\" alt=\"내장 디자인 시스템 라이브러리.\">\n<em>디자인 시스템 라이브러리: 실제 브랜드 룩을 고르세요 — Airbnb, Airtable 등 다양하게 — 그러면 Open Design이 그 토큰, 색상, 타이포그래피를 여러분의 디자인으로 가져옵니다.</em></p>\n<ul>\n<li><strong>디자인 시스템</strong>은 브랜드의 룩을 토큰으로 정리한 <code>DESIGN.md</code>로 담아냅니다 — 기본 색상과 보조 색상, 타이포그래피, 간격까지. 하나를 미리 보면 팔레트를 처음부터 정의하는 대신 그 위에 바로 빌드할 수 있습니다.</li>\n<li><strong>템플릿</strong>은 프로토타입, 슬라이드, 그리고 이미지와 영상 생성을 모두 아우릅니다. 유형별로 필터링하고 마음에 드는 것을 포크해 시작점으로 삼으세요.</li>\n</ul>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/03-templates.webp\" alt=\"템플릿 라이브러리.\">\n<em>템플릿: 프로토타입, 슬라이드, 이미지, 영상 시작점 — 유형별로 필터링하고 포크해 시작하세요.</em></p>\n<p>무엇이든 설치하기 전에 웹에서 <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>에서 전체 라이브러리를 둘러볼 수 있습니다.</p>\n<h2 id=\"build-something\">무언가 만들어 보기</h2>\n<p>다음은 AI Automation이 실행하는 흐름을, 최신 릴리스에 맞게 다시 쓴 것입니다:</p>\n<ol>\n<li><strong>디자인 시스템을 고르세요.</strong> 마음에 드는 것을 — 가령 <strong>Airbnb</strong>를 — 골라 열어서 그 <code>DESIGN.md</code>와 토큰을 살펴보세요.</li>\n<li><strong>시작점으로 가져오세요.</strong> <strong>Share → Download as ZIP</strong>을 사용한 다음, 프로젝트에서 <strong>Import flat design ZIP</strong>을 선택하세요. 디자인이 작업 공간에 나타나 빌드할 준비가 됩니다.</li>\n<li><strong>원하는 변경을 프롬프트로 입력하세요.</strong> 평범한 말로 된 지시를 — <em>“배경을 어둡게 만들어 줄 수 있나요?”</em> — 입력해 보내세요. 에이전트가 디자인 시스템을 읽고 작업을 계획한 뒤 아티팩트의 새 버전을 만들어 냅니다.</li>\n<li><strong>자유롭게 반복하세요.</strong> 글꼴을 바꾸고, 로고를 추가하거나 제거하고, 자신의 에셋을 업로드해 알맞은 자리에 배치되도록 하세요. 프롬프트마다 새로운 시안이 나오니 마음에 드는 것은 남기고 아닌 것은 버리세요.</li>\n<li><strong>만족스러우면 내보내세요.</strong> <strong>Share</strong>를 눌러 결과를 ZIP으로 내려받으세요.</li>\n</ol>\n<p>결과물은 연결한 모델이 구동한 진짜 편집 가능한 디자인입니다 — 그래서 유능한 에이전트는 결과물에 직접적으로 보답합니다.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">더 잘 활용하기 위한 팁</h2>\n<ul>\n<li><strong>강력한 모델을 고르세요.</strong> 출력 품질은 연결한 에이전트를 따라갑니다 — 흐름을 익히는 데는 무료 모델로도 충분하지만, 실제 작업에는 유능한 모델이 그만한 값을 합니다.</li>\n<li><strong>매번 출력된 URL을 읽으세요.</strong> 로컬 주소는 동적입니다. 예전 링크를 재사용하지 말고 <code>tools-dev</code>가 출력하는 것을 복사하세요.</li>\n<li><strong>Open Design이 찾는 곳에 에이전트를 설치하세요.</strong> WSL에서 소스로 실행 중인가요? CLI를 Ubuntu 내부에 설치해 작업 공간이 감지하도록 하세요. 데스크톱 앱은 Windows의 <code>PATH</code>를 읽습니다.</li>\n<li><strong>시작하는 데 디자인 시스템이 꼭 필요한 것은 아닙니다.</strong> 내장 시스템에서 시작하거나, ZIP을 가져오거나, Open Design이 기본값을 추론하도록 두세요. 디자인은 프로젝트 폴더에 함께 보관되므로, 올바른 디렉터리를 대상으로 실행해 작업을 정리하세요.</li>\n</ul>\n<h2 id=\"faq\">자주 묻는 질문</h2>\n<p><strong>Open Design은 무료인가요?</strong>\n네 — Apache-2.0 라이선스 아래의 오픈소스입니다. 로컬에서 무료로 실행할 수 있으며, 연결하는 에이전트와 미디어 공급자의 모델/API 사용료만 지불하면 됩니다.</p>\n<p><strong>WSL을 써야 하나요, 아니면 Windows 데스크톱 앱을 써야 하나요?</strong>\n대부분의 사람에게는 네이티브 Windows (x64) 데스크톱 빌드가 더 간단합니다 — WSL도, Node도, 복제도 필요 없습니다. 코드를 직접 읽거나 수정하고 싶을 때 WSL 소스 빌드 경로를 사용하세요. 참고로 WSL2는 주요 지원 경로이고 Windows 네이티브는 최선 노력(best-effort) 수준이니, 한쪽에서 마찰이 생기면 다른 쪽을 시도해 보세요.</p>\n<p><strong>어떤 코딩 에이전트를 지원하나요?</strong>\n21개 이상의 에이전트로, Claude Code, Codex, Cursor, Gemini, GitHub Copilot, OpenCode를 포함합니다. Open Design은 컴퓨터에 이미 설치된 CLI를 감지합니다 — 소스 경로에서는 WSL 내부에서, 데스크톱 앱에서는 Windows의 <code>PATH</code>에서.</p>\n<p><strong>Claude Design과는 어떻게 다른가요?</strong>\n익숙한 느낌은 같지만, 오픈소스이고 로컬 우선이며 에이전트 플러그인 방식입니다 — 그래서 하나의 모델에 묶이거나 정해진 크레딧 풀을 소진하지 않습니다. 또한 슬라이드 덱, 매거진 레이아웃, 이미지 생성, 영상으로 프로토타입 그 이상을 해냅니다.</p>\n<hr>\n<p><em>이 글로 된 가이드는 AI Automation의 Windows 설치 실습 영상을 바탕으로 합니다. 위의 전체 영상을 보고, 더 많은 실전 AI 도구 영상을 보려면 <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">AI Automation을 구독하세요</a>.</em></p>",
  },
  "de": {
    title: "Tschüss, Claude Design! Das ist der BESTE Open-Source-KI-UI-Generator",
    summary: "Installiere und starte Open Design unter Windows 11 — der einfache native Desktop-Build sowie der Weg aus dem Quellcode über WSL mit Node 24 und pnpm. Lass den Open-Source-KI-UI-Generator lokal laufen, ohne Cloud-Abo. Basierend auf dem Walkthrough von AI Automation.",
    bodyHtml: "<p>Diese Anleitung richtet sich an Windows-Nutzer, die Open Design auf dem eigenen Rechner laufen lassen wollen — ohne Cloud-Konto und ohne monatliche Credits, die man verbrauchen muss. Sie folgt dem Weg, den AI Automation in <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">ihrem Windows-Installations-Walkthrough</a> einschlägt, neu geschrieben und auf die aktuelle Version gebracht, damit du Befehl für Befehl mitmachen kannst. Sieh dir das Video oben für den Live-Durchlauf an oder lies hier die schriftliche Fassung.</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/01-workspace.webp\" alt=\"Der lokal laufende Open-Design-Arbeitsbereich.\">\n<em>Open Design läuft lokal unter Windows: ein quelloffener, agentennativer Design-Arbeitsbereich, den du vollständig selbst kontrollierst.</em></p>\n<h2 id=\"what-is-open-design\">Was ist Open Design?</h2>\n<p>Open Design ist eine quelloffene, lokal-zuerst arbeitende Design-Plattform — eine agentennative Alternative zu Claude Design und Figma. Statt dich auf einen einzigen Modellanbieter festzulegen, läuft es <strong>auf dem Coding-Agenten, den du ohnehin schon nutzt</strong>: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode und ein Dutzend weitere. Es ist „Bring deinen eigenen Agenten“ statt nur „Bring deinen eigenen Schlüssel“.</p>\n<p>Ein paar Dinge, die es lohnenswert machen:</p>\n<ul>\n<li><strong>Open Source, Apache-2.0</strong> — klone es, hoste es selbst, lies jede Zeile.</li>\n<li><strong>Läuft lokal</strong> — deine Projekte liegen in deinen eigenen Ordnern auf deinem Rechner, nicht in der Cloud eines anderen.</li>\n<li><strong>Agenten-steckbar</strong> — über 21 Coding-Agenten werden unterstützt; du wählst, welche CLI die Generierung antreibt, und die Qualität der Ausgabe richtet sich nach dem gewählten Modell.</li>\n<li><strong>Mehr als Prototypen</strong> — Prototypen, Live-Artefakte, Folien-Decks, Magazin-Layouts, Bildgenerierung und sogar Video, alles aus einem Arbeitsbereich.</li>\n<li><strong>Eine integrierte Bibliothek aus Designsystemen und Vorlagen</strong>, sodass du nicht vor einer leeren Leinwand startest.</li>\n</ul>\n<p>Wenn du Claude Design schon benutzt hast, wird dir das Gefühl sofort vertraut sein — Open Design behält dieselbe ruhige Ästhetik bei und legt dann Fähigkeiten (und deine Modellauswahl) obendrauf.</p>\n<h2 id=\"before-you-start\">Bevor du loslegst</h2>\n<p>Es gibt drei Wege, Open Design unter Windows zu installieren. Wähle den, der zu dir passt:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Weg</th><th>Am besten geeignet für</th><th>Voraussetzungen</th></tr></thead><tbody><tr><td><strong>Desktop-App (Windows x64)</strong></td><td>Die meisten Windows-Nutzer — ohne Konfiguration</td><td>Keine. Herunterladen und öffnen.</td></tr><tr><td><strong>Aus dem Quellcode ausführen (WSL)</strong></td><td>Entwickler, die den Code lesen oder ändern wollen</td><td>WSL2 + Ubuntu, Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>In deinen Agenten installieren</strong></td><td>Leute, die im Terminal leben</td><td>Eine vorhandene Coding-Agent-CLI</td></tr></tbody></table>\n<p>Das Video nutzt den Weg aus dem Quellcode über WSL, der großartig ist, wenn du im Repo arbeiten möchtest. Für die meisten ist aber der <strong>native Windows-Desktop-Build der empfohlene Weg</strong> — es gibt einen Windows-(x64)-Installer, der weder WSL noch Node noch ein Klonen benötigt. Diese Anleitung behandelt beides; der WSL-Walkthrough weiter unten ist für den Fall, dass du gezielt den Quellcode-Weg willst.</p>\n<h2 id=\"step-1--set-up-wsl\">Schritt 1 — WSL einrichten</h2>\n<p>Wenn du nur die Desktop-App möchtest, springe weiter zu Schritt 2, Option A. Willst du den Quellcode-Weg, brauchst du zuerst eine Linux-Umgebung innerhalb von Windows. Genau das liefert WSL (Windows Subsystem for Linux) — eine echte Ubuntu-Shell, die neben Windows läuft, ohne Dual-Boot und ohne eine virtuelle Maschine, die man bemuttern muss.</p>\n<p><strong>1. WSL und Ubuntu installieren.</strong> Öffne PowerShell und führe <code>wsl --install</code> aus — das aktiviert WSL2 und installiert standardmäßig Ubuntu. Starte neu, falls Windows danach fragt, starte dann <strong>Ubuntu</strong> über das Startmenü und lege beim ersten Öffnen deinen Linux-Benutzernamen und dein Passwort fest. (Du hast Ubuntu bereits von einem anderen Tool? Nimm es einfach weiter — das musst du nicht wiederholen.)</p>\n<p><strong>2. Die Basispakete aktualisieren.</strong> Aktualisiere in der Ubuntu-Shell den Paketindex und installiere die nötigsten Pakete:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> update</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#6E7448\"> -y</span><span style=\"color:#6E7448\"> curl</span><span style=\"color:#6E7448\"> git</span></span></code></pre>\n<blockquote>\n<p><strong>Tipp zur Fehlerbehebung aus dem Video:</strong> Wenn ein späterer Schritt einen seltsamen Fehler auswirft, starte deine Linux-Instanz sauber neu — führe in PowerShell <code>wsl --shutdown</code> aus und öffne dann Ubuntu erneut. Ein Neustart beseitigt die meisten Anlaufschwierigkeiten beim ersten Durchlauf.</p>\n</blockquote>\n<p><strong>3. Node 24 installieren.</strong> Der Quellcode-Build zielt auf Node <code>~24</code> ab. Ein frisches Ubuntu hat noch kein <code>nvm</code>, also installiere es zuerst und hole damit dann Node 24:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">curl</span><span style=\"color:#6E7448\"> -o-</span><span style=\"color:#6E7448\"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.3/install.sh</span><span style=\"color:#ED6F5C\"> |</span><span style=\"color:#15140F;font-weight:bold\"> bash</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">source</span><span style=\"color:#6E7448\"> ~/.bashrc</span><span style=\"color:#8B8676;font-style:italic\">            # nvm in die aktuelle Shell laden</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> use</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">node</span><span style=\"color:#6E7448\"> --version</span><span style=\"color:#8B8676;font-style:italic\">              # sollte v24.x ausgeben</span></span></code></pre>\n<p>Mit eingerichtetem Ubuntu und aktivem Node 24 bist du bereit, Open Design zu installieren.</p>\n<h2 id=\"step-2--install-open-design\">Schritt 2 — Open Design installieren</h2>\n<h3 id=\"option-a--windows-desktop-app-recommended-zero-config\">Option A — Windows-Desktop-App (empfohlen, ohne Konfiguration)</h3>\n<p>Gehe zu <a href=\"https://open-design.ai/\">open-design.ai</a> und klicke auf <strong>Download desktop</strong>. Es gibt einen nativen <strong>Windows-(x64)</strong>-Build (neben macOS und Linux). Führe den Installer aus, öffne die App, und sie erkennt automatisch jede Coding-Agent-CLI, die bereits in deinem <code>PATH</code> liegt, und lädt dann die integrierten Skills und Designsysteme für dich. Kein WSL, kein Terminal — das ist der einfachste Weg unter Windows.</p>\n<h3 id=\"option-b--run-from-source-inside-wsl\">Option B — Aus dem Quellcode ausführen (innerhalb von WSL)</h3>\n<p>Das ist der Weg, den AI Automation vorführt. Klone in deiner Ubuntu-Shell mit aktivem Node 24 das Repository und starte die Web-Laufzeitumgebung:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p><code>corepack enable</code> lässt Corepack die im Repo festgelegte pnpm-Version (<code>10.33.x</code>) wählen, sodass du pnpm nicht selbst installierst. <code>pnpm install</code> holt die Abhängigkeiten und kompiliert native Bestandteile — beim ersten Durchlauf kann das ein paar Minuten dauern, was zu erwarten ist und kein Fehler. <code>pnpm tools-dev run web</code> bootet anschließend den lokalen Daemon und den Webserver.</p>\n<p>Wenn es fertig ist, <strong>gibt der Befehl eine lokale URL aus</strong> — kopiere sie und füge sie in deinen <strong>Windows-Browser</strong> ein. WSL leitet den Port automatisch nach Windows durch, sodass sich die App einfach öffnet.</p>\n<blockquote>\n<p><strong>Wichtig:</strong> Der Port wird beim Start <strong>dynamisch zugewiesen</strong> — lies die Adresse, die der Befehl tatsächlich ausgibt. Gehe nicht von einem festen Port aus; die Adresse kann auf deinem Rechner und zwischen Durchläufen abweichen.</p>\n</blockquote>\n<h3 id=\"option-c--install-into-your-coding-agent-wsl\">Option C — In deinen Coding-Agenten installieren (WSL)</h3>\n<p>Du möchtest die GUI überspringen und Open Design als MCP-Server in deinem Agenten aufrufen? Unter WSL gibt es <strong>zuerst einen zusätzlichen Schritt</strong>. Linux liefert bereits <code>/usr/bin/od</code> (das Octal-Dump-Tool) mit, das das eigene <code>od</code> von Open Design verdeckt — sodass <code>od mcp install …</code> sonst mit „file not found“ für <code>mcp</code>/<code>install</code> fehlschlüge. Füge einen kleinen Wrapper hinzu, der <code>od</code> auf deinen Klon zeigen lässt, und stelle ihn an den Anfang von <code>PATH</code>:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">mkdir</span><span style=\"color:#6E7448\"> -p</span><span style=\"color:#6E7448\"> ~/.local/bin</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cat</span><span style=\"color:#ED6F5C\"> ></span><span style=\"color:#6E7448\"> ~/.local/bin/od</span><span style=\"color:#ED6F5C\"> &#x3C;&#x3C;</span><span style=\"color:#5A5448\">'EOF'</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">#!/usr/bin/env bash</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">repo=\"$HOME/open-design\"     # der ~/open-design-Klon aus Option B</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">cd \"$repo\" || exit 127</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">exec corepack pnpm exec od \"$@\"</span></span>\n<span class=\"line\"><span style=\"color:#5A5448\">EOF</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">chmod</span><span style=\"color:#6E7448\"> +x</span><span style=\"color:#6E7448\"> ~/.local/bin/od</span></span>\n<span class=\"line\"><span style=\"color:#ED6F5C\">export</span><span style=\"color:#2A2620\"> PATH</span><span style=\"color:#ED6F5C\">=</span><span style=\"color:#5A5448\">\"</span><span style=\"color:#2A2620\">$HOME</span><span style=\"color:#6E7448\">/.local/bin:</span><span style=\"color:#2A2620\">$PATH</span><span style=\"color:#5A5448\">\"</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">hash</span><span style=\"color:#6E7448\"> -r</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">type</span><span style=\"color:#6E7448\"> -a</span><span style=\"color:#6E7448\"> od</span><span style=\"color:#8B8676;font-style:italic\">                   # jetzt sollte das od von Open Design gewinnen</span></span></code></pre>\n<p>Verdrahte es dann mit deinem Agenten:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">od</span><span style=\"color:#6E7448\"> mcp</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> &#x3C;</span><span style=\"color:#6E7448\">agen</span><span style=\"color:#15140F\">t</span><span style=\"color:#ED6F5C\">></span></span>\n<span class=\"line\"><span style=\"color:#8B8676;font-style:italic\"># &#x3C;agent> = claude | codex | cursor | copilot | gemini | opencode | …</span></span></code></pre>\n<p>Bitte den Agenten dann einfach: <code>Use open-design to generate a landing page with the Airbnb design system</code>.</p>\n<h2 id=\"first-run-connect-your-coding-agent\">Erster Start: Verbinde deinen Coding-Agenten</h2>\n<p>Beim ersten Laden des Arbeitsbereichs scannt Open Design deine Umgebung und zeigt jede gefundene CLI an. Da WSL eine echte Linux-Box ist, erfasst es Agenten, die <strong>innerhalb von Ubuntu</strong> installiert sind — eine Gemini-CLI oder ein anderer Agent, der in WSL lebt, wird also dort erkannt. Klicke auf <strong>rescan</strong>, wenn etwas noch nicht auftaucht.</p>\n<ul>\n<li><strong>Wähle einen Standard-Agenten und ein Modell.</strong> Lass die installierte CLI die Generierung antreiben oder richte sie auf einen bestimmten Anbieter und ein bestimmtes Modell aus. Wie das Video betont, bedeutet ein stärkeres Modell merklich bessere Ausgaben — greife also zu einem leistungsfähigen, wenn das Ergebnis zählt.</li>\n<li><strong>Füge Medienanbieter hinzu (optional).</strong> Um Bilder, Video oder Audio zu erzeugen, füge deine eigenen API-Schlüssel ein — Bring-deinen-eigenen-Schlüssel, nur für die Anbieter, die du tatsächlich nutzt.</li>\n<li><strong>Verbinde MCP-Dienste (optional).</strong> Binde Konnektoren ein, wenn der Agent aus anderen Quellen ziehen soll.</li>\n<li><strong>Lege Einstellungen fest.</strong> Sprache, Erscheinungsbild, Benachrichtigungen — sogar ein Desktop-Haustier. All das kannst du später ändern, halte den ersten Durchgang also einfach.</li>\n</ul>\n<h2 id=\"explore-the-workspace\">Den Arbeitsbereich erkunden</h2>\n<p>Open Design hält deine Arbeit <strong>projektbezogen</strong>: Wenn du es gegen einen Ordner ausführst, leben die Designs, die du erstellst, in diesem Projektverzeichnis. Deine erste Projektliste wird leer sein — das ist normal.</p>\n<p>Innerhalb eines Projekts kannst du Prototypen, Folien-Decks, Bilder, Videos und mehr bauen. Zwei Ausgangspunkte lassen die leere Leinwand verschwinden:</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/02-design-systems.webp\" alt=\"Die integrierte Bibliothek der Designsysteme.\">\n<em>Die Designsystem-Bibliothek: Wähle einen echten Markenlook — Airbnb, Airtable und viele weitere — und Open Design überträgt dessen Tokens, Farben und Typografie in dein Design.</em></p>\n<ul>\n<li><strong>Designsysteme</strong> fassen den Look einer Marke als <code>DESIGN.md</code> aus Tokens — Primär- und Sekundärfarben, Typografie, Abstände. Sieh dir eines in der Vorschau an, und du kannst direkt darauf aufbauen, statt eine Palette von Grund auf zu definieren.</li>\n<li><strong>Vorlagen</strong> decken Prototypen, Folien sowie Bild- und Videogenerierung ab. Filtere nach Typ und forke eine beliebige als Startvorsprung.</li>\n</ul>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/03-templates.webp\" alt=\"Die Vorlagenbibliothek.\">\n<em>Vorlagen: Ausgangspunkte für Prototyp, Folie, Bild und Video — filtere nach Typ und forke, um zu starten.</em></p>\n<p>Du kannst die vollständige Bibliothek vor dem Installieren von allem im Web unter <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> durchstöbern.</p>\n<h2 id=\"build-something\">Etwas bauen</h2>\n<p>Hier ist der Ablauf, den AI Automation durchspielt, neu geschrieben für die aktuelle Version:</p>\n<ol>\n<li><strong>Wähle ein Designsystem.</strong> Suche dir eins aus, das dir gefällt — etwa <strong>Airbnb</strong> — und öffne es, um seine <code>DESIGN.md</code> und Tokens zu inspizieren.</li>\n<li><strong>Importiere es als Ausgangspunkt.</strong> Verwende <strong>Share → Download as ZIP</strong> und wähle dann in deinem Projekt <strong>Import flat design ZIP</strong>. Das Design erscheint im Arbeitsbereich, bereit zum Aufbauen.</li>\n<li><strong>Beschreibe die gewünschte Änderung als Prompt.</strong> Tippe ein Briefing in einfacher Sprache — <em>„Kannst du den Hintergrund dunkel machen?“</em> — und sende es ab. Der Agent liest das Designsystem, plant seine Arbeit und erzeugt eine neue Version des Artefakts.</li>\n<li><strong>Iteriere nach Belieben.</strong> Ändere Schriften, füge ein Logo hinzu oder entferne es, lade eigene Assets hoch und lass sie an den richtigen Stellen platzieren. Jeder Prompt liefert einen frischen Entwurf zum Behalten oder Verwerfen.</li>\n<li><strong>Exportiere, wenn du zufrieden bist.</strong> Klicke auf <strong>Share</strong> und lade das Ergebnis als ZIP herunter.</li>\n</ol>\n<p>Die Ausgabe ist ein echtes, bearbeitbares Design, angetrieben von dem Modell, das du verbunden hast — ein leistungsfähiger Agent zahlt sich also direkt in dem aus, was du zurückbekommst.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Tipps, um mehr herauszuholen</h2>\n<ul>\n<li><strong>Wähle ein starkes Modell.</strong> Die Ausgabequalität richtet sich nach dem verbundenen Agenten — ein kostenloses Modell reicht, um den Ablauf zu lernen, aber für echte Arbeit lohnt sich ein leistungsfähiges.</li>\n<li><strong>Lies jedes Mal die ausgegebene URL.</strong> Die lokale Adresse ist dynamisch; kopiere, was <code>tools-dev</code> ausgibt, statt einen alten Link wiederzuverwenden.</li>\n<li><strong>Installiere deine Agenten dort, wo Open Design sucht.</strong> Führst du aus dem Quellcode in WSL aus? Installiere deine CLIs innerhalb von Ubuntu, damit der Arbeitsbereich sie erkennt; die Desktop-App liest deinen Windows-<code>PATH</code>.</li>\n<li><strong>Du brauchst kein Designsystem, um zu starten.</strong> Beginne mit einem integrierten, importiere ein ZIP oder lass Open Design Standardwerte ableiten. Deine Designs bleiben beim Projektordner, organisiere die Arbeit also, indem du sie gegen das richtige Verzeichnis ausführst.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Ist Open Design kostenlos?</strong>\nJa — es ist Open Source unter der Apache-2.0-Lizenz. Du kannst es lokal kostenlos ausführen; du zahlst nur für die Modell-/API-Nutzung des jeweiligen Agenten und der Medienanbieter, die du verbindest.</p>\n<p><strong>Soll ich WSL oder die Windows-Desktop-App verwenden?</strong>\nFür die meisten ist der native Windows-(x64)-Desktop-Build einfacher — kein WSL, kein Node, kein Klonen. Nutze den WSL-Quellcode-Weg, wenn du gezielt den Code lesen oder ändern möchtest. Beachte, dass WSL2 ein primär unterstützter Weg ist, während Windows-nativ nach bestem Bemühen (best-effort) läuft; falls du bei dem einen auf Reibung stößt, probiere den anderen.</p>\n<p><strong>Welche Coding-Agenten werden unterstützt?</strong>\nÜber 21 Agenten, darunter Claude Code, Codex, Cursor, Gemini, GitHub Copilot und OpenCode. Open Design erkennt die CLIs, die bereits auf deinem Rechner installiert sind — innerhalb von WSL für den Quellcode-Weg oder in deinem Windows-<code>PATH</code> für die Desktop-App.</p>\n<p><strong>Wie unterscheidet es sich von Claude Design?</strong>\nDasselbe vertraute Gefühl, aber quelloffen, lokal-zuerst und agenten-steckbar — du bist also nicht auf ein Modell festgelegt und verbrennst keinen festen Credit-Pool. Außerdem geht es über Prototypen hinaus, mit Folien-Decks, Magazin-Layouts, Bildgenerierung und Video.</p>\n<hr>\n<p><em>Diese schriftliche Anleitung basiert auf dem Windows-Installations-Walkthrough von AI Automation. Sieh dir das vollständige Video oben an und <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">abonniere AI Automation</a> für weitere praxisnahe Videos zu KI-Tools.</em></p>",
  },
  "fr": {
    title: "Adieu Claude Design ! Voici le MEILLEUR générateur d'UI par IA open source",
    summary: "Installez et lancez Open Design sur Windows 11 — la version desktop native simple, ainsi que la voie depuis les sources via WSL avec Node 24 et pnpm. Faites tourner le générateur d'UI par IA open source en local, sans abonnement cloud. D'après le tutoriel d'AI Automation.",
    bodyHtml: "<p>Ce guide s'adresse aux utilisateurs de Windows qui veulent faire tourner Open Design sur leur propre machine — sans compte cloud, sans crédits mensuels à consommer. Il suit la voie empruntée par AI Automation dans <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">leur tutoriel d'installation sur Windows</a>, réécrit et mis à jour avec la version actuelle pour que vous puissiez suivre commande par commande. Regardez la vidéo ci-dessus pour la démonstration en direct, ou poursuivez votre lecture pour la version écrite.</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/01-workspace.webp\" alt=\"L'espace de travail Open Design tournant en local.\">\n<em>Open Design tournant en local sur Windows : un espace de travail de conception open source et agent-native que vous contrôlez entièrement.</em></p>\n<h2 id=\"what-is-open-design\">Qu'est-ce qu'Open Design ?</h2>\n<p>Open Design est une plateforme de conception open source et local-first — une alternative agent-native à Claude Design et Figma. Au lieu de vous enfermer chez un seul fournisseur de modèle, elle s'appuie <strong>sur l'agent de code que vous utilisez déjà</strong> : Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode, et une douzaine d'autres. C'est du « apportez votre propre agent » plutôt que simplement apportez votre propre clé.</p>\n<p>Quelques points qui valent le détour :</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — clonez-le, auto-hébergez-le, lisez chaque ligne.</li>\n<li><strong>Tourne en local</strong> — vos projets vivent dans vos propres dossiers sur votre machine, pas dans le cloud de quelqu'un d'autre.</li>\n<li><strong>Agents enfichables</strong> — plus de 21 agents de code sont pris en charge ; vous choisissez quel CLI pilote la génération, et la qualité du résultat suit le modèle que vous retenez.</li>\n<li><strong>Bien plus que des prototypes</strong> — prototypes, artefacts vivants, présentations, mises en page de type magazine, génération d'images, et même de la vidéo, le tout depuis un seul espace de travail.</li>\n<li><strong>Une bibliothèque intégrée de design systems et de modèles</strong>, pour ne pas partir d'une toile blanche.</li>\n</ul>\n<p>Si vous avez utilisé Claude Design, la prise en main sera immédiatement familière — Open Design conserve la même esthétique apaisée, puis ajoute des capacités (et le choix de votre modèle) par-dessus.</p>\n<h2 id=\"before-you-start\">Avant de commencer</h2>\n<p>Vous avez trois façons d'installer Open Design sur Windows. Choisissez celle qui vous convient :</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Voie</th><th>Idéale pour</th><th>Prérequis</th></tr></thead><tbody><tr><td><strong>Application desktop (Windows x64)</strong></td><td>La plupart des utilisateurs de Windows — zéro configuration</td><td>Aucun. Téléchargez et ouvrez.</td></tr><tr><td><strong>Lancer depuis les sources (WSL)</strong></td><td>Les développeurs qui veulent lire ou modifier le code</td><td>WSL2 + Ubuntu, Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Installer dans votre agent</strong></td><td>Ceux qui vivent dans le terminal</td><td>Un CLI d'agent de code déjà installé</td></tr></tbody></table>\n<p>La vidéo utilise la voie depuis les sources via WSL, parfaite si vous voulez vivre à l'intérieur du dépôt. Mais pour la plupart des gens, la <strong>version desktop native de Windows est la voie recommandée</strong> — il existe un installeur Windows (x64) qui ne nécessite ni WSL, ni Node, ni clone. Ce guide couvre les deux ; le tutoriel WSL ci-dessous est réservé aux cas où vous voulez spécifiquement la voie des sources.</p>\n<h2 id=\"step-1--set-up-wsl\">Étape 1 — Configurer WSL</h2>\n<p>Si vous voulez seulement l'application desktop, passez directement à l'Étape 2, Option A. Si vous voulez la voie depuis les sources, il vous faut d'abord un environnement Linux à l'intérieur de Windows. C'est exactement ce que fournit WSL (Windows Subsystem for Linux) — un véritable shell Ubuntu tournant aux côtés de Windows, sans dual-boot, sans machine virtuelle à surveiller.</p>\n<p><strong>1. Installez WSL et Ubuntu.</strong> Ouvrez PowerShell et exécutez <code>wsl --install</code> — cela active WSL2 et installe Ubuntu par défaut. Redémarrez si Windows le demande, puis lancez <strong>Ubuntu</strong> depuis le menu Démarrer et définissez votre nom d'utilisateur et votre mot de passe Linux au premier lancement. (Vous avez déjà Ubuntu via un autre outil ? Réutilisez-le — inutile de recommencer.)</p>\n<p><strong>2. Mettez à jour les paquets de base.</strong> Dans le shell Ubuntu, actualisez l'index des paquets et installez l'essentiel :</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> update</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#6E7448\"> -y</span><span style=\"color:#6E7448\"> curl</span><span style=\"color:#6E7448\"> git</span></span></code></pre>\n<blockquote>\n<p><strong>Astuce de dépannage tirée de la vidéo :</strong> si une étape ultérieure renvoie une erreur étrange, redémarrez proprement votre instance Linux — depuis PowerShell, exécutez <code>wsl --shutdown</code>, puis rouvrez Ubuntu. Un démarrage à neuf règle la plupart des accrocs du premier lancement.</p>\n</blockquote>\n<p><strong>3. Installez Node 24.</strong> La version depuis les sources cible Node <code>~24</code>. Un Ubuntu propre n'a pas encore <code>nvm</code>, alors installez-le d'abord, puis utilisez-le pour obtenir Node 24 :</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">curl</span><span style=\"color:#6E7448\"> -o-</span><span style=\"color:#6E7448\"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.3/install.sh</span><span style=\"color:#ED6F5C\"> |</span><span style=\"color:#15140F;font-weight:bold\"> bash</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">source</span><span style=\"color:#6E7448\"> ~/.bashrc</span><span style=\"color:#8B8676;font-style:italic\">            # charge nvm dans le shell courant</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> use</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">node</span><span style=\"color:#6E7448\"> --version</span><span style=\"color:#8B8676;font-style:italic\">              # devrait afficher v24.x</span></span></code></pre>\n<p>Une fois Ubuntu configuré et Node 24 actif, vous êtes prêt à installer Open Design.</p>\n<h2 id=\"step-2--install-open-design\">Étape 2 — Installer Open Design</h2>\n<h3 id=\"option-a--windows-desktop-app-recommended-zero-config\">Option A — Application desktop Windows (recommandée, zéro configuration)</h3>\n<p>Rendez-vous sur <a href=\"https://open-design.ai/\">open-design.ai</a> et cliquez sur <strong>Download desktop</strong>. Il existe une version native <strong>Windows (x64)</strong> (en plus de macOS et Linux). Lancez l'installeur, ouvrez l'application, et elle détecte automatiquement chaque CLI d'agent de code déjà présent dans votre <code>PATH</code>, puis charge pour vous les skills et design systems intégrés. Pas de WSL, pas de terminal — c'est la voie la plus simple sur Windows.</p>\n<h3 id=\"option-b--run-from-source-inside-wsl\">Option B — Lancer depuis les sources (à l'intérieur de WSL)</h3>\n<p>C'est la voie que démontre AI Automation. En travaillant dans votre shell Ubuntu avec Node 24 actif, clonez le dépôt et démarrez le runtime web :</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p><code>corepack enable</code> permet à Corepack de sélectionner la version de pnpm épinglée dans le dépôt (<code>10.33.x</code>), pour que vous n'ayez pas à installer pnpm vous-même. <code>pnpm install</code> récupère les dépendances et compile les composants natifs — cela peut prendre quelques minutes au premier lancement, ce qui est attendu, pas un échec. <code>pnpm tools-dev run web</code> démarre ensuite le daemon local et le serveur web.</p>\n<p>Une fois terminé, la commande <strong>affiche une URL locale</strong> — copiez-la et collez-la dans votre <strong>navigateur Windows</strong>. WSL redirige automatiquement le port vers Windows, l'application s'ouvre donc directement.</p>\n<blockquote>\n<p><strong>Important :</strong> le port est <strong>attribué dynamiquement</strong> au lancement — lisez l'adresse réelle que la commande affiche. Ne supposez pas un port fixe ; l'adresse peut différer d'une machine à l'autre et d'un lancement à l'autre.</p>\n</blockquote>\n<h3 id=\"option-c--install-into-your-coding-agent-wsl\">Option C — Installer dans votre agent de code (WSL)</h3>\n<p>Vous préférez ignorer l'interface graphique et appeler Open Design comme serveur MCP à l'intérieur de votre agent ? Sur WSL, il y a <strong>une étape supplémentaire au préalable</strong>. Linux fournit déjà <code>/usr/bin/od</code> (l'outil de dump octal), qui masque le <code>od</code> propre à Open Design — sans quoi <code>od mcp install …</code> échouerait avec « file not found » pour <code>mcp</code>/<code>install</code>. Ajoutez un petit wrapper qui pointe <code>od</code> vers votre clone et placez-le en tête du <code>PATH</code> :</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">mkdir</span><span style=\"color:#6E7448\"> -p</span><span style=\"color:#6E7448\"> ~/.local/bin</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cat</span><span style=\"color:#ED6F5C\"> ></span><span style=\"color:#6E7448\"> ~/.local/bin/od</span><span style=\"color:#ED6F5C\"> &#x3C;&#x3C;</span><span style=\"color:#5A5448\">'EOF'</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">#!/usr/bin/env bash</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">repo=\"$HOME/open-design\"     # le clone ~/open-design de l'Option B</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">cd \"$repo\" || exit 127</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">exec corepack pnpm exec od \"$@\"</span></span>\n<span class=\"line\"><span style=\"color:#5A5448\">EOF</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">chmod</span><span style=\"color:#6E7448\"> +x</span><span style=\"color:#6E7448\"> ~/.local/bin/od</span></span>\n<span class=\"line\"><span style=\"color:#ED6F5C\">export</span><span style=\"color:#2A2620\"> PATH</span><span style=\"color:#ED6F5C\">=</span><span style=\"color:#5A5448\">\"</span><span style=\"color:#2A2620\">$HOME</span><span style=\"color:#6E7448\">/.local/bin:</span><span style=\"color:#2A2620\">$PATH</span><span style=\"color:#5A5448\">\"</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">hash</span><span style=\"color:#6E7448\"> -r</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">type</span><span style=\"color:#6E7448\"> -a</span><span style=\"color:#6E7448\"> od</span><span style=\"color:#8B8676;font-style:italic\">                   # le od d'Open Design devrait désormais l'emporter</span></span></code></pre>\n<p>Reliez-le ensuite à votre agent :</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">od</span><span style=\"color:#6E7448\"> mcp</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> &#x3C;</span><span style=\"color:#6E7448\">agen</span><span style=\"color:#15140F\">t</span><span style=\"color:#ED6F5C\">></span></span>\n<span class=\"line\"><span style=\"color:#8B8676;font-style:italic\"># &#x3C;agent> = claude | codex | cursor | copilot | gemini | opencode | …</span></span></code></pre>\n<p>Ensuite, à l'intérieur de l'agent, il suffit de demander : <code>Use open-design to generate a landing page with the Airbnb design system</code>.</p>\n<h2 id=\"first-run-connect-your-coding-agent\">Premier lancement : connecter votre agent de code</h2>\n<p>Au premier chargement de l'espace de travail, Open Design analyse votre environnement et affiche chaque CLI trouvé. Comme WSL est une véritable machine Linux, il repère les agents installés <strong>à l'intérieur d'Ubuntu</strong> — un CLI Gemini ou un autre agent vivant dans WSL y est donc détecté. Cliquez sur <strong>rescan</strong> si quelque chose ne s'affiche pas encore.</p>\n<ul>\n<li><strong>Choisissez un agent et un modèle par défaut.</strong> Laissez le CLI installé piloter la génération, ou pointez-le vers un fournisseur et un modèle précis. Comme le souligne la vidéo, un modèle plus puissant donne un résultat nettement meilleur, alors optez pour un modèle capable quand le résultat compte.</li>\n<li><strong>Ajoutez des fournisseurs de médias (facultatif).</strong> Pour générer des images, de la vidéo ou de l'audio, collez vos propres clés API — bring-your-own-key, uniquement pour les fournisseurs que vous utilisez réellement.</li>\n<li><strong>Connectez des services MCP (facultatif).</strong> Branchez des connecteurs si vous voulez que l'agent puise dans d'autres sources.</li>\n<li><strong>Définissez vos préférences.</strong> Langue, apparence, notifications — et même un animal de compagnie de bureau. Vous pourrez tout modifier plus tard, alors gardez le premier passage simple.</li>\n</ul>\n<h2 id=\"explore-the-workspace\">Explorer l'espace de travail</h2>\n<p>Open Design garde votre travail <strong>cantonné au projet</strong> : quand vous le lancez sur un dossier, les designs que vous créez vivent à l'intérieur de ce répertoire de projet. Votre première liste de projets sera vide — c'est normal.</p>\n<p>Au sein d'un projet, vous pouvez construire des prototypes, des présentations, des images, des vidéos, et plus encore. Deux points de départ font disparaître la toile blanche :</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/02-design-systems.webp\" alt=\"La bibliothèque intégrée de design systems.\">\n<em>La bibliothèque de design systems : choisissez l'apparence d'une vraie marque — Airbnb, Airtable, et bien d'autres — et Open Design en transpose les tokens, couleurs et typographie dans votre design.</em></p>\n<ul>\n<li>Les <strong>design systems</strong> capturent l'apparence d'une marque sous la forme d'un <code>DESIGN.md</code> de tokens — couleurs primaires et secondaires, typographie, espacement. Prévisualisez-en un, et vous pouvez construire directement par-dessus au lieu de définir une palette de zéro.</li>\n<li>Les <strong>modèles</strong> couvrent les prototypes, les présentations, ainsi que la génération d'images et de vidéos. Filtrez par type et forkez n'importe lequel pour prendre de l'avance.</li>\n</ul>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/03-templates.webp\" alt=\"La bibliothèque de modèles.\">\n<em>Modèles : des points de départ pour prototypes, présentations, images et vidéos — filtrez par type et forkez pour commencer.</em></p>\n<p>Vous pouvez parcourir toute la bibliothèque sur le web à l'adresse <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> avant d'installer quoi que ce soit.</p>\n<h2 id=\"build-something\">Créer quelque chose</h2>\n<p>Voici le déroulé que suit AI Automation, réécrit pour la version actuelle :</p>\n<ol>\n<li><strong>Choisissez un design system.</strong> Optez pour celui qui vous plaît — disons <strong>Airbnb</strong> — et ouvrez-le pour inspecter son <code>DESIGN.md</code> et ses tokens.</li>\n<li><strong>Importez-le comme point de départ.</strong> Utilisez <strong>Share → Download as ZIP</strong>, puis dans votre projet choisissez <strong>Import flat design ZIP</strong>. Le design apparaît dans l'espace de travail, prêt à servir de base.</li>\n<li><strong>Formulez le changement souhaité.</strong> Tapez un brief en langage clair — <em>« Peux-tu rendre l'arrière-plan sombre ? »</em> — et envoyez-le. L'agent lit le design system, planifie son travail, et produit une nouvelle version de l'artefact.</li>\n<li><strong>Itérez librement.</strong> Changez les polices, ajoutez ou supprimez un logo, téléversez vos propres ressources et faites-les placer au bon endroit. Chaque prompt produit une nouvelle proposition à conserver ou à écarter.</li>\n<li><strong>Exportez quand le résultat vous convient.</strong> Cliquez sur <strong>Share</strong> et téléchargez le résultat sous forme de ZIP.</li>\n</ol>\n<p>Le résultat est un design réel et modifiable, piloté par le modèle que vous avez connecté — un agent capable se traduit donc directement par ce que vous récupérez.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Conseils pour en tirer davantage</h2>\n<ul>\n<li><strong>Choisissez un modèle puissant.</strong> La qualité du résultat suit l'agent que vous connectez — un modèle gratuit suffit pour apprendre le déroulé, mais un modèle capable vaut le coup pour le vrai travail.</li>\n<li><strong>Lisez l'URL affichée à chaque fois.</strong> L'adresse locale est dynamique ; copiez ce que <code>tools-dev</code> affiche plutôt que de réutiliser un ancien lien.</li>\n<li><strong>Installez vos agents là où Open Design ira chercher.</strong> Vous lancez depuis les sources dans WSL ? Installez vos CLI à l'intérieur d'Ubuntu pour que l'espace de travail les détecte ; l'application desktop, elle, lit votre <code>PATH</code> Windows.</li>\n<li><strong>Vous n'avez pas besoin d'un design system pour démarrer.</strong> Partez d'un design intégré, importez un ZIP, ou laissez Open Design déduire des valeurs par défaut. Vos designs restent attachés au dossier du projet, alors organisez votre travail en le lançant sur le bon répertoire.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Open Design est-il gratuit ?</strong>\nOui — il est open source sous licence Apache-2.0. Vous pouvez le faire tourner en local gratuitement ; vous ne payez que l'usage du modèle/de l'API de l'agent et des fournisseurs de médias que vous connectez.</p>\n<p><strong>Dois-je utiliser WSL ou l'application desktop Windows ?</strong>\nPour la plupart des gens, la version desktop native Windows (x64) est plus simple — pas de WSL, pas de Node, pas de clone. Utilisez la voie depuis les sources via WSL quand vous voulez spécifiquement lire ou modifier le code. À noter : WSL2 est une voie principale prise en charge, tandis que le natif Windows est au mieux-effort ; si vous rencontrez des frictions avec l'une, essayez l'autre.</p>\n<p><strong>Quels agents de code prend-il en charge ?</strong>\nPlus de 21 agents, dont Claude Code, Codex, Cursor, Gemini, GitHub Copilot et OpenCode. Open Design détecte les CLI déjà installés sur votre machine — à l'intérieur de WSL pour la voie des sources, ou sur votre <code>PATH</code> Windows pour l'application desktop.</p>\n<p><strong>En quoi diffère-t-il de Claude Design ?</strong>\nLa même prise en main familière, mais open source, local-first et avec agents enfichables — vous n'êtes donc pas enfermé chez un seul modèle ni à consommer un pool de crédits fixe. Il va aussi au-delà des prototypes avec des présentations, des mises en page de type magazine, de la génération d'images et de la vidéo.</p>\n<hr>\n<p><em>Ce guide écrit s'appuie sur le tutoriel d'installation sur Windows d'AI Automation. Regardez la vidéo complète ci-dessus, et <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">abonnez-vous à AI Automation</a> pour plus de vidéos pratiques sur les outils d'IA.</em></p>",
  },
  "ru": {
    title: "Прощай, Claude Design! Это ЛУЧШИЙ генератор UI на ИИ с открытым кодом",
    summary: "Установите и запустите Open Design в Windows 11 — простая нативная сборка для десктопа, а также способ запуска из исходников через WSL с Node 24 и pnpm. Запускайте генератор UI на ИИ с открытым кодом локально, без облачной подписки. По мотивам разбора от AI Automation.",
    bodyHtml: "<p>Это руководство для пользователей Windows, которые хотят запустить Open Design на собственной машине — без облачной учётной записи, без ежемесячных кредитов, которые нужно расходовать. Оно следует пути, который проходит AI Automation в <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">своём разборе установки на Windows</a>, переписанному и обновлённому под текущий релиз, чтобы вы могли повторять шаг за шагом, команда за командой. Посмотрите видео выше, чтобы увидеть всё вживую, или читайте дальше — это текстовая версия.</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/01-workspace.webp\" alt=\"Рабочее пространство Open Design, запущенное локально.\">\n<em>Open Design, запущенный локально в Windows: рабочее пространство для дизайна с открытым кодом и agent-native подходом, которое вы полностью контролируете.</em></p>\n<h2 id=\"what-is-open-design\">Что такое Open Design?</h2>\n<p>Open Design — это платформа для дизайна с открытым кодом и приоритетом локальной работы, agent-native альтернатива Claude Design и Figma. Вместо того чтобы привязывать вас к одному поставщику моделей, она работает <strong>поверх того агента для написания кода, которым вы уже пользуетесь</strong>: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode и ещё с десяток других. Это «принеси своего агента», а не просто «принеси свой ключ».</p>\n<p>Несколько вещей, ради которых на это стоит взглянуть:</p>\n<ul>\n<li><strong>Открытый код, Apache-2.0</strong> — клонируйте, разворачивайте у себя, читайте каждую строку.</li>\n<li><strong>Работает локально</strong> — ваши проекты живут в ваших собственных папках на вашей машине, а не в чужом облаке.</li>\n<li><strong>Подключаемые агенты</strong> — поддерживается 21+ агент для написания кода; вы выбираете, какой CLI управляет генерацией, и качество результата зависит от выбранной вами модели.</li>\n<li><strong>Больше, чем прототипы</strong> — прототипы, живые артефакты, слайд-деки, журнальные макеты, генерация изображений и даже видео — всё из одного рабочего пространства.</li>\n<li><strong>Встроенная библиотека дизайн-систем и шаблонов</strong>, так что вы начинаете не с чистого холста.</li>\n</ul>\n<p>Если вы пользовались Claude Design, ощущение будет мгновенно знакомым — Open Design сохраняет ту же спокойную эстетику, а затем добавляет поверх неё возможности (и выбор модели).</p>\n<h2 id=\"before-you-start\">Прежде чем начать</h2>\n<p>Установить Open Design в Windows можно тремя способами. Выберите тот, что подходит вам:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Способ</th><th>Кому подходит</th><th>Требования</th></tr></thead><tbody><tr><td><strong>Десктопное приложение (Windows x64)</strong></td><td>Большинству пользователей Windows — без настройки</td><td>Ничего. Скачать и открыть.</td></tr><tr><td><strong>Запуск из исходников (WSL)</strong></td><td>Разработчикам, которые хотят читать или менять код</td><td>WSL2 + Ubuntu, Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Установка в ваш агент</strong></td><td>Тем, кто живёт в терминале</td><td>Уже установленный CLI агента для написания кода</td></tr></tbody></table>\n<p>В видео используется путь через WSL с запуском из исходников — отличный вариант, если вы хотите жить внутри репозитория. Но для большинства <strong>рекомендуемым путём является нативная десктопная сборка для Windows</strong> — есть установщик для Windows (x64), которому не нужны ни WSL, ни Node, ни клонирование. Это руководство охватывает оба варианта; разбор WSL ниже — для тех случаев, когда вам конкретно нужен путь через исходники.</p>\n<h2 id=\"step-1--set-up-wsl\">Шаг 1 — Настройте WSL</h2>\n<p>Если вам нужно только десктопное приложение, переходите сразу к Шагу 2, Вариант A. Если вы хотите путь из исходников, сначала вам понадобится среда Linux внутри Windows. Именно это и предоставляет WSL (Windows Subsystem for Linux) — настоящая оболочка Ubuntu, работающая рядом с Windows, без двойной загрузки и без виртуальной машины, за которой нужно присматривать.</p>\n<p><strong>1. Установите WSL и Ubuntu.</strong> Откройте PowerShell и выполните <code>wsl --install</code> — это включает WSL2 и устанавливает Ubuntu по умолчанию. Перезагрузитесь, если Windows попросит, затем запустите <strong>Ubuntu</strong> из меню «Пуск» и задайте имя пользователя и пароль Linux при первом запуске. (Уже есть Ubuntu от другого инструмента? Используйте его повторно — повторять это не нужно.)</p>\n<p><strong>2. Обновите базовые пакеты.</strong> Внутри оболочки Ubuntu обновите индекс пакетов и установите необходимое:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> update</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#6E7448\"> -y</span><span style=\"color:#6E7448\"> curl</span><span style=\"color:#6E7448\"> git</span></span></code></pre>\n<blockquote>\n<p><strong>Совет по устранению неполадок из видео:</strong> если на одном из следующих шагов возникнет странная ошибка, чисто перезапустите свой экземпляр Linux — из PowerShell выполните <code>wsl --shutdown</code>, затем снова откройте Ubuntu. Свежий старт устраняет большинство мелких проблем первого запуска.</p>\n</blockquote>\n<p><strong>3. Установите Node 24.</strong> Сборка из исходников рассчитана на Node <code>~24</code>. В чистой Ubuntu ещё нет <code>nvm</code>, поэтому сначала установите его, а затем используйте, чтобы получить Node 24:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">curl</span><span style=\"color:#6E7448\"> -o-</span><span style=\"color:#6E7448\"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.3/install.sh</span><span style=\"color:#ED6F5C\"> |</span><span style=\"color:#15140F;font-weight:bold\"> bash</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">source</span><span style=\"color:#6E7448\"> ~/.bashrc</span><span style=\"color:#8B8676;font-style:italic\">            # загрузить nvm в текущую оболочку</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> use</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">node</span><span style=\"color:#6E7448\"> --version</span><span style=\"color:#8B8676;font-style:italic\">              # должно вывести v24.x</span></span></code></pre>\n<p>Когда Ubuntu настроена и Node 24 активен, вы готовы устанавливать Open Design.</p>\n<h2 id=\"step-2--install-open-design\">Шаг 2 — Установите Open Design</h2>\n<h3 id=\"option-a--windows-desktop-app-recommended-zero-config\">Вариант A — Десктопное приложение для Windows (рекомендуется, без настройки)</h3>\n<p>Перейдите на <a href=\"https://open-design.ai/\">open-design.ai</a> и нажмите <strong>Download desktop</strong>. Есть нативная сборка для <strong>Windows (x64)</strong> (наряду с macOS и Linux). Запустите установщик, откройте приложение — и оно автоматически обнаружит каждый CLI агента для написания кода, уже присутствующий в вашем <code>PATH</code>, а затем загрузит для вас встроенные навыки и дизайн-системы. Ни WSL, ни терминала — это самый простой путь в Windows.</p>\n<h3 id=\"option-b--run-from-source-inside-wsl\">Вариант B — Запуск из исходников (внутри WSL)</h3>\n<p>Это путь, который демонстрирует AI Automation. Работая внутри оболочки Ubuntu с активным Node 24, клонируйте репозиторий и запустите веб-среду выполнения:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p><code>corepack enable</code> позволяет Corepack выбрать версию pnpm, закреплённую в репозитории (<code>10.33.x</code>), так что вам не нужно устанавливать pnpm самостоятельно. <code>pnpm install</code> подтягивает зависимости и компилирует нативные части — при первом запуске это может занять пару минут, что ожидаемо, а не сбой. Затем <code>pnpm tools-dev run web</code> запускает локальный демон и веб-сервер.</p>\n<p>Когда всё завершится, команда <strong>выведет локальный URL</strong> — скопируйте его и вставьте в <strong>браузер Windows</strong>. WSL автоматически пробрасывает порт в Windows, так что приложение просто откроется.</p>\n<blockquote>\n<p><strong>Важно:</strong> порт <strong>назначается динамически</strong> при запуске — читайте фактический адрес, который выводит команда. Не предполагайте фиксированный порт; адрес может отличаться на вашей машине и от запуска к запуску.</p>\n</blockquote>\n<h3 id=\"option-c--install-into-your-coding-agent-wsl\">Вариант C — Установка в ваш агент для написания кода (WSL)</h3>\n<p>Предпочитаете обойтись без GUI и вызывать Open Design как MCP-сервер внутри своего агента? В WSL сначала есть <strong>один дополнительный шаг</strong>. Linux уже поставляется с <code>/usr/bin/od</code> (инструмент восьмеричного дампа), который перекрывает собственный <code>od</code> от Open Design — поэтому иначе <code>od mcp install …</code> завершился бы с «file not found» для <code>mcp</code>/<code>install</code>. Добавьте небольшую обёртку, которая направляет <code>od</code> на ваш клон, и поставьте её первой в <code>PATH</code>:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">mkdir</span><span style=\"color:#6E7448\"> -p</span><span style=\"color:#6E7448\"> ~/.local/bin</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cat</span><span style=\"color:#ED6F5C\"> ></span><span style=\"color:#6E7448\"> ~/.local/bin/od</span><span style=\"color:#ED6F5C\"> &#x3C;&#x3C;</span><span style=\"color:#5A5448\">'EOF'</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">#!/usr/bin/env bash</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">repo=\"$HOME/open-design\"     # the ~/open-design clone from Option B</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">cd \"$repo\" || exit 127</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">exec corepack pnpm exec od \"$@\"</span></span>\n<span class=\"line\"><span style=\"color:#5A5448\">EOF</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">chmod</span><span style=\"color:#6E7448\"> +x</span><span style=\"color:#6E7448\"> ~/.local/bin/od</span></span>\n<span class=\"line\"><span style=\"color:#ED6F5C\">export</span><span style=\"color:#2A2620\"> PATH</span><span style=\"color:#ED6F5C\">=</span><span style=\"color:#5A5448\">\"</span><span style=\"color:#2A2620\">$HOME</span><span style=\"color:#6E7448\">/.local/bin:</span><span style=\"color:#2A2620\">$PATH</span><span style=\"color:#5A5448\">\"</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">hash</span><span style=\"color:#6E7448\"> -r</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">type</span><span style=\"color:#6E7448\"> -a</span><span style=\"color:#6E7448\"> od</span><span style=\"color:#8B8676;font-style:italic\">                   # теперь должен побеждать od от Open Design</span></span></code></pre>\n<p>Затем подключите это к своему агенту:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">od</span><span style=\"color:#6E7448\"> mcp</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> &#x3C;</span><span style=\"color:#6E7448\">agen</span><span style=\"color:#15140F\">t</span><span style=\"color:#ED6F5C\">></span></span>\n<span class=\"line\"><span style=\"color:#8B8676;font-style:italic\"># &#x3C;agent> = claude | codex | cursor | copilot | gemini | opencode | …</span></span></code></pre>\n<p>А затем внутри агента просто попросите: <code>Use open-design to generate a landing page with the Airbnb design system</code>.</p>\n<h2 id=\"first-run-connect-your-coding-agent\">Первый запуск: подключите свой агент для написания кода</h2>\n<p>При первой загрузке рабочего пространства Open Design сканирует ваше окружение и показывает каждый найденный CLI. Поскольку WSL — это настоящая Linux-машина, он подхватывает агентов, установленных <strong>внутри Ubuntu</strong> — так что Gemini CLI или другой агент, живущий в WSL, обнаруживается именно там. Нажмите <strong>rescan</strong> (повторное сканирование), если что-то ещё не появилось.</p>\n<ul>\n<li><strong>Выберите агент и модель по умолчанию.</strong> Доверьте генерацию установленному CLI или укажите конкретного поставщика и модель. Как подчёркивается в видео, более сильная модель означает заметно лучший результат, так что выбирайте мощную, когда результат важен.</li>\n<li><strong>Добавьте поставщиков медиа (необязательно).</strong> Чтобы генерировать изображения, видео или аудио, вставьте собственные API-ключи — принцип «принеси свой ключ», только для тех поставщиков, которыми вы действительно пользуетесь.</li>\n<li><strong>Подключите MCP-сервисы (необязательно).</strong> Подключите коннекторы, если хотите, чтобы агент брал данные из других источников.</li>\n<li><strong>Задайте настройки.</strong> Язык, оформление, уведомления — и даже настольный питомец. Всё это можно изменить позже, так что на первый раз не усложняйте.</li>\n</ul>\n<h2 id=\"explore-the-workspace\">Изучите рабочее пространство</h2>\n<p>Open Design держит вашу работу <strong>в рамках проекта</strong>: когда вы запускаете его в какой-то папке, создаваемые вами дизайны живут внутри этого каталога проекта. Ваш первый список проектов будет пустым — это нормально.</p>\n<p>Внутри проекта вы можете создавать прототипы, слайд-деки, изображения, видео и многое другое. Две отправные точки заставят чистый холст исчезнуть:</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/02-design-systems.webp\" alt=\"Встроенная библиотека дизайн-систем.\">\n<em>Библиотека дизайн-систем: выберите облик настоящего бренда — Airbnb, Airtable и многие другие — и Open Design перенесёт его токены, цвета и типографику в ваш дизайн.</em></p>\n<ul>\n<li><strong>Дизайн-системы</strong> фиксируют облик бренда в виде <code>DESIGN.md</code> с токенами — основные и дополнительные цвета, типографика, отступы. Просмотрите её — и можно строить прямо поверх неё, вместо того чтобы определять палитру с нуля.</li>\n<li><strong>Шаблоны</strong> охватывают прототипы, слайды, а также генерацию изображений и видео. Фильтруйте по типу и форкайте любой, чтобы стартовать с форы.</li>\n</ul>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/03-templates.webp\" alt=\"Библиотека шаблонов.\">\n<em>Шаблоны: отправные точки для прототипов, слайдов, изображений и видео — фильтруйте по типу и форкайте, чтобы начать.</em></p>\n<p>Вы можете просмотреть всю библиотеку в вебе на <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>, прежде чем что-либо устанавливать.</p>\n<h2 id=\"build-something\">Создайте что-нибудь</h2>\n<p>Вот процесс, который проходит AI Automation, переписанный под текущий релиз:</p>\n<ol>\n<li><strong>Выберите дизайн-систему.</strong> Выберите ту, что вам по душе — скажем, <strong>Airbnb</strong> — и откройте её, чтобы изучить её <code>DESIGN.md</code> и токены.</li>\n<li><strong>Импортируйте её как отправную точку.</strong> Используйте <strong>Share → Download as ZIP</strong>, затем в своём проекте выберите <strong>Import flat design ZIP</strong>. Дизайн появится в рабочем пространстве, готовый к работе.</li>\n<li><strong>Опишите в запросе нужное изменение.</strong> Введите бриф простым языком — <em>«Можешь сделать фон тёмным?»</em> — и отправьте. Агент читает дизайн-систему, планирует свою работу и создаёт новую версию артефакта.</li>\n<li><strong>Свободно итерируйте.</strong> Меняйте шрифты, добавляйте или убирайте логотип, загружайте собственные ассеты и размещайте их в нужных местах. Каждый запрос порождает свежий вариант, который можно оставить или отбросить.</li>\n<li><strong>Экспортируйте, когда довольны.</strong> Нажмите <strong>Share</strong> и скачайте результат в виде ZIP.</li>\n</ol>\n<p>На выходе — настоящий, редактируемый дизайн, управляемый подключённой вами моделью, так что мощный агент напрямую окупается в том, что вы получаете обратно.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Советы, как извлечь больше</h2>\n<ul>\n<li><strong>Выбирайте сильную модель.</strong> Качество результата зависит от подключённого агента — бесплатная модель сгодится, чтобы освоить процесс, но для серьёзной работы мощная того стоит.</li>\n<li><strong>Каждый раз читайте выведенный URL.</strong> Локальный адрес динамичен; копируйте то, что выводит <code>tools-dev</code>, а не используйте старую ссылку повторно.</li>\n<li><strong>Устанавливайте агентов там, где Open Design будет искать.</strong> Запускаете из исходников в WSL? Устанавливайте свои CLI внутри Ubuntu, чтобы рабочее пространство их обнаружило; десктопное приложение читает ваш <code>PATH</code> в Windows.</li>\n<li><strong>Чтобы начать, дизайн-система не обязательна.</strong> Начните со встроенной, импортируйте ZIP или позвольте Open Design определить значения по умолчанию. Ваши дизайны остаются с папкой проекта, так что организуйте работу, запускаясь в нужном каталоге.</li>\n</ul>\n<h2 id=\"faq\">Часто задаваемые вопросы</h2>\n<p><strong>Open Design бесплатен?</strong>\nДа — это открытый код под лицензией Apache-2.0. Вы можете запускать его локально бесплатно; платите вы только за использование модели/API того агента и поставщиков медиа, которых подключаете.</p>\n<p><strong>Что выбрать — WSL или десктопное приложение для Windows?</strong>\nДля большинства людей нативная десктопная сборка для Windows (x64) проще — ни WSL, ни Node, ни клонирования. Используйте путь через WSL из исходников, когда вам конкретно нужно читать или менять код. Учтите, что WSL2 — это основной поддерживаемый путь, тогда как Windows-нативный вариант — по мере возможности; если с одним возникнут сложности, попробуйте другой.</p>\n<p><strong>Какие агенты для написания кода он поддерживает?</strong>\n21+ агент, включая Claude Code, Codex, Cursor, Gemini, GitHub Copilot и OpenCode. Open Design обнаруживает CLI, уже установленные на вашей машине — внутри WSL для пути из исходников или в вашем <code>PATH</code> Windows для десктопного приложения.</p>\n<p><strong>Чем он отличается от Claude Design?</strong>\nТо же знакомое ощущение, но открытый код, приоритет локальной работы и подключаемые агенты — так что вы не привязаны к одной модели и не расходуете фиксированный пул кредитов. Он также выходит за рамки прототипов: слайд-деки, журнальные макеты, генерация изображений и видео.</p>\n<hr>\n<p><em>Это текстовое руководство основано на разборе установки на Windows от AI Automation. Посмотрите полное видео выше и <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">подпишитесь на AI Automation</a>, чтобы увидеть больше практичных видео об ИИ-инструментах.</em></p>",
  },
  "es": {
    title: "¡ADIÓS, Claude Design! Este es el MEJOR generador de UI con IA de código abierto",
    summary: "Instala y ejecuta Open Design en Windows 11: la sencilla versión de escritorio nativa, además de la ruta desde el código fuente a través de WSL con Node 24 y pnpm. Ejecuta el generador de UI con IA de código abierto en local, sin suscripción a la nube. Basado en el tutorial de AI Automation.",
    bodyHtml: "<p>Esta guía es para usuarios de Windows que quieren ejecutar Open Design en su propia máquina, sin cuenta en la nube ni créditos mensuales que gastar. Sigue el camino que toma AI Automation en <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">su tutorial de instalación en Windows</a>, reescrito y actualizado a la versión actual para que puedas seguirlo comando a comando. Mira el vídeo de arriba para ver la ejecución en directo, o continúa leyendo para la versión escrita.</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/01-workspace.webp\" alt=\"El espacio de trabajo de Open Design ejecutándose en local.\">\n<em>Open Design ejecutándose en local en Windows: un espacio de trabajo de diseño de código abierto y nativo de agentes que controlas por completo.</em></p>\n<h2 id=\"what-is-open-design\">¿Qué es Open Design?</h2>\n<p>Open Design es una plataforma de diseño de código abierto y local-first: una alternativa nativa de agentes a Claude Design y Figma. En lugar de atarte a un único proveedor de modelos, se ejecuta <strong>sobre el agente de programación que ya usas</strong>: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode y una docena más. Es «trae tu propio agente» en lugar de solo traer tu propia clave.</p>\n<p>Algunas cosas que hacen que merezca la pena echarle un vistazo:</p>\n<ul>\n<li><strong>Código abierto, Apache-2.0</strong>: clónalo, autoalójalo, lee cada línea.</li>\n<li><strong>Se ejecuta en local</strong>: tus proyectos viven en tus propias carpetas, en tu máquina, no en la nube de otra persona.</li>\n<li><strong>Conectable a agentes</strong>: admite más de 21 agentes de programación; tú eliges qué CLI impulsa la generación, y la calidad del resultado depende del modelo que elijas.</li>\n<li><strong>Más que prototipos</strong>: prototipos, artefactos en vivo, presentaciones, maquetaciones tipo revista, generación de imágenes e incluso vídeo, todo desde un mismo espacio de trabajo.</li>\n<li><strong>Una biblioteca integrada de sistemas de diseño y plantillas</strong>, para que no empieces desde un lienzo en blanco.</li>\n</ul>\n<p>Si has usado Claude Design, la sensación te resultará familiar al instante: Open Design conserva la misma estética serena y, encima, añade capacidades (y la elección de tu modelo).</p>\n<h2 id=\"before-you-start\">Antes de empezar</h2>\n<p>Tienes tres formas de instalar Open Design en Windows. Elige la que mejor te encaje:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Ruta</th><th>Ideal para</th><th>Requisitos</th></tr></thead><tbody><tr><td><strong>App de escritorio (Windows x64)</strong></td><td>La mayoría de usuarios de Windows: cero configuración</td><td>Ninguno. Descarga y abre.</td></tr><tr><td><strong>Ejecutar desde el código fuente (WSL)</strong></td><td>Desarrolladores que quieren leer o modificar el código</td><td>WSL2 + Ubuntu, Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Instalar en tu agente</strong></td><td>Personas que viven en la terminal</td><td>Una CLI de agente de programación existente</td></tr></tbody></table>\n<p>El vídeo usa la ruta desde el código fuente con WSL, que es ideal si quieres vivir dentro del repositorio. Pero para la mayoría de la gente la <strong>versión de escritorio nativa de Windows es la ruta recomendada</strong>: hay un instalador de Windows (x64) que no necesita WSL, ni Node, ni clonar nada. Esta guía cubre ambas; el tutorial de WSL de más abajo es para cuando quieras específicamente la ruta desde el código fuente.</p>\n<h2 id=\"step-1--set-up-wsl\">Paso 1: configurar WSL</h2>\n<p>Si solo quieres la app de escritorio, salta al Paso 2, Opción A. Si quieres la ruta desde el código fuente, primero necesitas un entorno Linux dentro de Windows. Eso es exactamente lo que ofrece WSL (Subsistema de Windows para Linux): una shell de Ubuntu real ejecutándose junto a Windows, sin arranque dual ni una máquina virtual de la que estar pendiente.</p>\n<p><strong>1. Instala WSL y Ubuntu.</strong> Abre PowerShell y ejecuta <code>wsl --install</code>: esto activa WSL2 e instala Ubuntu de forma predeterminada. Reinicia si Windows lo pide, luego abre <strong>Ubuntu</strong> desde el menú de Inicio y define tu nombre de usuario y contraseña de Linux la primera vez que se abra. (¿Ya tienes Ubuntu de otra herramienta? Reutilízalo, no hace falta repetir esto.)</p>\n<p><strong>2. Actualiza los paquetes base.</strong> Dentro de la shell de Ubuntu, refresca el índice de paquetes e instala lo esencial:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> update</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#6E7448\"> -y</span><span style=\"color:#6E7448\"> curl</span><span style=\"color:#6E7448\"> git</span></span></code></pre>\n<blockquote>\n<p><strong>Consejo de resolución de problemas del vídeo:</strong> si un paso posterior lanza un error extraño, reinicia tu instancia de Linux de forma limpia: desde PowerShell ejecuta <code>wsl --shutdown</code> y luego vuelve a abrir Ubuntu. Empezar de cero resuelve la mayoría de los tropiezos de la primera ejecución.</p>\n</blockquote>\n<p><strong>3. Instala Node 24.</strong> La versión desde el código fuente apunta a Node <code>~24</code>. Una instalación limpia de Ubuntu aún no tiene <code>nvm</code>, así que instálalo primero y luego úsalo para obtener Node 24:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">curl</span><span style=\"color:#6E7448\"> -o-</span><span style=\"color:#6E7448\"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.3/install.sh</span><span style=\"color:#ED6F5C\"> |</span><span style=\"color:#15140F;font-weight:bold\"> bash</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">source</span><span style=\"color:#6E7448\"> ~/.bashrc</span><span style=\"color:#8B8676;font-style:italic\">            # carga nvm en la shell actual</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> use</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">node</span><span style=\"color:#6E7448\"> --version</span><span style=\"color:#8B8676;font-style:italic\">              # debería imprimir v24.x</span></span></code></pre>\n<p>Con Ubuntu configurado y Node 24 activo, ya estás listo para instalar Open Design.</p>\n<h2 id=\"step-2--install-open-design\">Paso 2: instalar Open Design</h2>\n<h3 id=\"option-a--windows-desktop-app-recommended-zero-config\">Opción A: app de escritorio de Windows (recomendada, cero configuración)</h3>\n<p>Ve a <a href=\"https://open-design.ai/\">open-design.ai</a> y haz clic en <strong>Download desktop</strong>. Hay una versión nativa para <strong>Windows (x64)</strong> (junto con las de macOS y Linux). Ejecuta el instalador, abre la app y detectará automáticamente todas las CLI de agentes de programación que ya estén en tu <code>PATH</code>, luego cargará por ti las skills y los sistemas de diseño integrados. Sin WSL, sin terminal: esta es la ruta más sencilla en Windows.</p>\n<h3 id=\"option-b--run-from-source-inside-wsl\">Opción B: ejecutar desde el código fuente (dentro de WSL)</h3>\n<p>Esta es la ruta que demuestra AI Automation. Trabajando dentro de tu shell de Ubuntu con Node 24 activo, clona el repositorio e inicia el runtime web:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p><code>corepack enable</code> permite que Corepack seleccione la versión de pnpm fijada en el repositorio (<code>10.33.x</code>), por lo que no instalas pnpm tú mismo. <code>pnpm install</code> descarga las dependencias y compila las piezas nativas; esto puede tardar un par de minutos en la primera ejecución, lo cual es esperable, no un fallo. <code>pnpm tools-dev run web</code> arranca después el daemon local y el servidor web.</p>\n<p>Cuando termina, el comando <strong>imprime una URL local</strong>: cópiala y pégala en tu <strong>navegador de Windows</strong>. WSL reenvía el puerto a Windows automáticamente, así que la app simplemente se abre.</p>\n<blockquote>\n<p><strong>Importante:</strong> el puerto se <strong>asigna de forma dinámica</strong> al arrancar: lee la dirección real que imprime el comando. No des por hecho un puerto fijo; la dirección puede variar en tu máquina y entre ejecuciones.</p>\n</blockquote>\n<h3 id=\"option-c--install-into-your-coding-agent-wsl\">Opción C: instalar en tu agente de programación (WSL)</h3>\n<p>¿Prefieres saltarte la interfaz gráfica y llamar a Open Design como servidor MCP dentro de tu agente? En WSL hay <strong>un paso extra primero</strong>. Linux ya incluye <code>/usr/bin/od</code> (la herramienta de volcado octal), que tapa el propio <code>od</code> de Open Design, así que <code>od mcp install …</code> fallaría de otro modo con «file not found» para <code>mcp</code>/<code>install</code>. Añade un pequeño wrapper que apunte <code>od</code> a tu clon y colócalo primero en el <code>PATH</code>:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">mkdir</span><span style=\"color:#6E7448\"> -p</span><span style=\"color:#6E7448\"> ~/.local/bin</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cat</span><span style=\"color:#ED6F5C\"> ></span><span style=\"color:#6E7448\"> ~/.local/bin/od</span><span style=\"color:#ED6F5C\"> &#x3C;&#x3C;</span><span style=\"color:#5A5448\">'EOF'</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">#!/usr/bin/env bash</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">repo=\"$HOME/open-design\"     # el clon ~/open-design de la Opción B</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">cd \"$repo\" || exit 127</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">exec corepack pnpm exec od \"$@\"</span></span>\n<span class=\"line\"><span style=\"color:#5A5448\">EOF</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">chmod</span><span style=\"color:#6E7448\"> +x</span><span style=\"color:#6E7448\"> ~/.local/bin/od</span></span>\n<span class=\"line\"><span style=\"color:#ED6F5C\">export</span><span style=\"color:#2A2620\"> PATH</span><span style=\"color:#ED6F5C\">=</span><span style=\"color:#5A5448\">\"</span><span style=\"color:#2A2620\">$HOME</span><span style=\"color:#6E7448\">/.local/bin:</span><span style=\"color:#2A2620\">$PATH</span><span style=\"color:#5A5448\">\"</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">hash</span><span style=\"color:#6E7448\"> -r</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">type</span><span style=\"color:#6E7448\"> -a</span><span style=\"color:#6E7448\"> od</span><span style=\"color:#8B8676;font-style:italic\">                   # ahora debería ganar el od de Open Design</span></span></code></pre>\n<p>Luego conéctalo a tu agente:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">od</span><span style=\"color:#6E7448\"> mcp</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> &#x3C;</span><span style=\"color:#6E7448\">agen</span><span style=\"color:#15140F\">t</span><span style=\"color:#ED6F5C\">></span></span>\n<span class=\"line\"><span style=\"color:#8B8676;font-style:italic\"># &#x3C;agent> = claude | codex | cursor | copilot | gemini | opencode | …</span></span></code></pre>\n<p>Luego, dentro del agente, simplemente pide: <code>Use open-design to generate a landing page with the Airbnb design system</code>.</p>\n<h2 id=\"first-run-connect-your-coding-agent\">Primera ejecución: conecta tu agente de programación</h2>\n<p>La primera vez que se carga el espacio de trabajo, Open Design escanea tu entorno y muestra todas las CLI que encontró. Como WSL es una máquina Linux real, detecta los agentes instalados <strong>dentro de Ubuntu</strong>, de modo que una CLI de Gemini u otro agente que viva en WSL se detecta allí. Haz clic en <strong>rescan</strong> si algo aún no aparece.</p>\n<ul>\n<li><strong>Elige un agente y un modelo por defecto.</strong> Deja que la CLI instalada impulse la generación, o apúntala a un proveedor y modelo concretos. Como recalca el vídeo, un modelo más potente significa resultados notablemente mejores, así que recurre a uno capaz cuando el resultado importe.</li>\n<li><strong>Añade proveedores multimedia (opcional).</strong> Para generar imágenes, vídeo o audio, pega tus propias claves de API: trae tu propia clave, solo para los proveedores que realmente uses.</li>\n<li><strong>Conecta servicios MCP (opcional).</strong> Conecta conectores si quieres que el agente extraiga datos de otras fuentes.</li>\n<li><strong>Configura tus preferencias.</strong> Idioma, apariencia, notificaciones, incluso una mascota de escritorio. Puedes cambiar todo esto más adelante, así que mantén la primera pasada simple.</li>\n</ul>\n<h2 id=\"explore-the-workspace\">Explora el espacio de trabajo</h2>\n<p>Open Design mantiene tu trabajo <strong>delimitado por proyecto</strong>: cuando lo ejecutas sobre una carpeta, los diseños que creas viven dentro del directorio de ese proyecto. Tu primera lista de proyectos estará vacía: eso es normal.</p>\n<p>Dentro de un proyecto puedes crear prototipos, presentaciones, imágenes, vídeos y más. Dos puntos de partida hacen desaparecer el lienzo en blanco:</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/02-design-systems.webp\" alt=\"La biblioteca integrada de sistemas de diseño.\">\n<em>La biblioteca de sistemas de diseño: elige el aspecto de una marca real (Airbnb, Airtable y muchas más) y Open Design lleva sus tokens, colores y tipografía a tu diseño.</em></p>\n<ul>\n<li>Los <strong>sistemas de diseño</strong> capturan el aspecto de una marca como un <code>DESIGN.md</code> de tokens: colores primarios y secundarios, tipografía, espaciado. Previsualiza uno y podrás construir directamente sobre él en lugar de definir una paleta desde cero.</li>\n<li>Las <strong>plantillas</strong> cubren prototipos, presentaciones y generación tanto de imagen como de vídeo. Filtra por tipo y bifurca cualquiera para arrancar con ventaja.</li>\n</ul>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/03-templates.webp\" alt=\"La biblioteca de plantillas.\">\n<em>Plantillas: puntos de partida para prototipo, presentación, imagen y vídeo; filtra por tipo y bifurca para empezar.</em></p>\n<p>Puedes explorar la biblioteca completa en la web en <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> antes de instalar nada.</p>\n<h2 id=\"build-something\">Crea algo</h2>\n<p>Este es el flujo que ejecuta AI Automation, reescrito para la versión actual:</p>\n<ol>\n<li><strong>Elige un sistema de diseño.</strong> Escoge uno que te guste —digamos <strong>Airbnb</strong>— y ábrelo para inspeccionar su <code>DESIGN.md</code> y sus tokens.</li>\n<li><strong>Impórtalo como punto de partida.</strong> Usa <strong>Share → Download as ZIP</strong> y luego, en tu proyecto, elige <strong>Import flat design ZIP</strong>. El diseño aparece en el espacio de trabajo, listo para construir sobre él.</li>\n<li><strong>Indica el cambio que quieres.</strong> Escribe un encargo en lenguaje natural —<em>«¿Puedes poner el fondo oscuro?»</em>— y envíalo. El agente lee el sistema de diseño, planifica su trabajo y produce una nueva versión del artefacto.</li>\n<li><strong>Itera con libertad.</strong> Cambia tipografías, añade o quita un logotipo, sube tus propios recursos y haz que se coloquen en los lugares adecuados. Cada prompt produce una propuesta nueva para conservar o descartar.</li>\n<li><strong>Exporta cuando estés satisfecho.</strong> Pulsa <strong>Share</strong> y descarga el resultado como un ZIP.</li>\n</ol>\n<p>El resultado es un diseño real y editable impulsado por el modelo que conectaste, así que un agente capaz se traduce directamente en lo que recibes.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Consejos para sacarle más partido</h2>\n<ul>\n<li><strong>Elige un modelo potente.</strong> La calidad del resultado depende del agente que conectes: un modelo gratuito sirve para aprender el flujo, pero uno capaz merece la pena para el trabajo real.</li>\n<li><strong>Lee la URL impresa cada vez.</strong> La dirección local es dinámica; copia lo que imprime <code>tools-dev</code> en lugar de reutilizar un enlace antiguo.</li>\n<li><strong>Instala tus agentes donde Open Design vaya a buscarlos.</strong> ¿Ejecutas desde el código fuente en WSL? Instala tus CLI dentro de Ubuntu para que el espacio de trabajo las detecte; la app de escritorio lee tu <code>PATH</code> de Windows.</li>\n<li><strong>No necesitas un sistema de diseño para empezar.</strong> Arranca desde uno integrado, importa un ZIP o deja que Open Design infiera valores por defecto. Tus diseños se quedan con la carpeta del proyecto, así que organiza el trabajo ejecutándolo sobre el directorio adecuado.</li>\n</ul>\n<h2 id=\"faq\">Preguntas frecuentes</h2>\n<p><strong>¿Open Design es gratis?</strong>\nSí: es de código abierto bajo la licencia Apache-2.0. Puedes ejecutarlo en local de forma gratuita; solo pagas por el uso del modelo/API de los agentes y proveedores multimedia que conectes.</p>\n<p><strong>¿Debería usar WSL o la app de escritorio de Windows?</strong>\nPara la mayoría de la gente, la versión de escritorio nativa de Windows (x64) es más simple: sin WSL, sin Node, sin clonar nada. Usa la ruta desde el código fuente con WSL cuando quieras específicamente leer o modificar el código. Ten en cuenta que WSL2 es una ruta soportada de forma primaria, mientras que la versión nativa de Windows es de mejor esfuerzo; si te encuentras con fricciones en una, prueba la otra.</p>\n<p><strong>¿Qué agentes de programación admite?</strong>\nMás de 21 agentes, entre ellos Claude Code, Codex, Cursor, Gemini, GitHub Copilot y OpenCode. Open Design detecta las CLI que ya tienes instaladas en tu máquina: dentro de WSL para la ruta desde el código fuente, o en tu <code>PATH</code> de Windows para la app de escritorio.</p>\n<p><strong>¿En qué se diferencia de Claude Design?</strong>\nLa misma sensación familiar, pero de código abierto, local-first y conectable a agentes, así que no quedas atado a un único modelo ni quemas una bolsa fija de créditos. Además va más allá de los prototipos con presentaciones, maquetaciones tipo revista, generación de imágenes y vídeo.</p>\n<hr>\n<p><em>Esta guía escrita se basa en el tutorial de instalación en Windows de AI Automation. Mira el vídeo completo arriba y <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">suscríbete a AI Automation</a> para más vídeos prácticos sobre herramientas de IA.</em></p>",
  },
  "pt-br": {
    title: "ADEUS, Claude Design! Este é o MELHOR gerador de UI com IA de código aberto",
    summary: "Instale e execute o Open Design no Windows 11 — a versão de desktop nativa e simples, além do caminho a partir do código-fonte via WSL com Node 24 e pnpm. Rode o gerador de UI com IA de código aberto localmente, sem assinatura na nuvem. Baseado no tutorial do AI Automation.",
    bodyHtml: "<p>Este guia é para usuários de Windows que querem rodar o Open Design na própria máquina — sem conta na nuvem, sem créditos mensais para gastar. Ele segue o caminho que o AI Automation percorre <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">no tutorial de instalação no Windows</a>, reescrito e atualizado para a versão atual para que você possa acompanhar comando a comando. Assista ao vídeo acima para ver a execução ao vivo, ou continue lendo para a versão escrita.</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/01-workspace.webp\" alt=\"O espaço de trabalho do Open Design rodando localmente.\">\n<em>Open Design rodando localmente no Windows: um espaço de trabalho de design de código aberto e nativo de agentes que você controla por completo.</em></p>\n<h2 id=\"what-is-open-design\">O que é o Open Design?</h2>\n<p>O Open Design é uma plataforma de design de código aberto e local-first — uma alternativa nativa de agentes ao Claude Design e ao Figma. Em vez de prendê-lo a um único provedor de modelo, ele roda <strong>sobre o agente de programação que você já usa</strong>: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode e mais uma dúzia. É «traga seu próprio agente» em vez de apenas trazer sua própria chave.</p>\n<p>Algumas coisas que fazem dele algo que vale a pena conhecer:</p>\n<ul>\n<li><strong>Código aberto, Apache-2.0</strong> — clone, hospede você mesmo, leia cada linha.</li>\n<li><strong>Roda localmente</strong> — seus projetos ficam nas suas próprias pastas, na sua máquina, não na nuvem de outra pessoa.</li>\n<li><strong>Plugável a agentes</strong> — mais de 21 agentes de programação são suportados; você escolhe qual CLI conduz a geração, e a qualidade do resultado acompanha o modelo que você escolher.</li>\n<li><strong>Mais do que protótipos</strong> — protótipos, artefatos ao vivo, apresentações de slides, layouts no estilo revista, geração de imagens e até vídeo, tudo a partir de um único espaço de trabalho.</li>\n<li><strong>Uma biblioteca integrada de design systems e templates</strong>, para que você não comece de uma tela em branco.</li>\n</ul>\n<p>Se você já usou o Claude Design, a sensação será imediatamente familiar — o Open Design mantém a mesma estética tranquila e, por cima, adiciona recursos (e a escolha do seu modelo).</p>\n<h2 id=\"before-you-start\">Antes de começar</h2>\n<p>Você tem três formas de instalar o Open Design no Windows. Escolha a que combina com você:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Caminho</th><th>Ideal para</th><th>Requisitos</th></tr></thead><tbody><tr><td><strong>App de desktop (Windows x64)</strong></td><td>A maioria dos usuários de Windows — zero configuração</td><td>Nenhum. Baixe e abra.</td></tr><tr><td><strong>Rodar a partir do código-fonte (WSL)</strong></td><td>Desenvolvedores que querem ler ou modificar o código</td><td>WSL2 + Ubuntu, Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Instalar no seu agente</strong></td><td>Quem vive no terminal</td><td>Uma CLI de agente de programação existente</td></tr></tbody></table>\n<p>O vídeo usa o caminho a partir do código-fonte via WSL, ótimo se você quer viver dentro do repositório. Mas, para a maioria das pessoas, a <strong>versão de desktop nativa do Windows é o caminho recomendado</strong> — há um instalador para Windows (x64) que não precisa de WSL, nem de Node, nem de clonar nada. Este guia cobre os dois; o tutorial de WSL abaixo é para quando você quiser especificamente o caminho a partir do código-fonte.</p>\n<h2 id=\"step-1--set-up-wsl\">Passo 1 — Configurar o WSL</h2>\n<p>Se você só quer o app de desktop, pule para o Passo 2, Opção A. Se quer o caminho a partir do código-fonte, primeiro precisa de um ambiente Linux dentro do Windows. É exatamente isso que o WSL (Subsistema do Windows para Linux) oferece — um shell Ubuntu real rodando ao lado do Windows, sem dual-boot, sem máquina virtual para ficar cuidando.</p>\n<p><strong>1. Instale o WSL e o Ubuntu.</strong> Abra o PowerShell e execute <code>wsl --install</code> — isso ativa o WSL2 e instala o Ubuntu por padrão. Reinicie se o Windows pedir, depois abra o <strong>Ubuntu</strong> pelo menu Iniciar e defina seu nome de usuário e senha do Linux na primeira vez que ele abrir. (Já tem o Ubuntu de outra ferramenta? Reutilize-o — não precisa repetir isso.)</p>\n<p><strong>2. Atualize os pacotes base.</strong> Dentro do shell do Ubuntu, atualize o índice de pacotes e instale o essencial:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> update</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#6E7448\"> -y</span><span style=\"color:#6E7448\"> curl</span><span style=\"color:#6E7448\"> git</span></span></code></pre>\n<blockquote>\n<p><strong>Dica de solução de problemas do vídeo:</strong> se um passo posterior lançar um erro estranho, reinicie sua instância do Linux de forma limpa — no PowerShell execute <code>wsl --shutdown</code> e depois reabra o Ubuntu. Começar do zero resolve a maioria dos tropeços da primeira execução.</p>\n</blockquote>\n<p><strong>3. Instale o Node 24.</strong> A versão a partir do código-fonte tem como alvo o Node <code>~24</code>. Um Ubuntu limpo ainda não tem o <code>nvm</code>, então instale-o primeiro e depois use-o para obter o Node 24:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">curl</span><span style=\"color:#6E7448\"> -o-</span><span style=\"color:#6E7448\"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.3/install.sh</span><span style=\"color:#ED6F5C\"> |</span><span style=\"color:#15140F;font-weight:bold\"> bash</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">source</span><span style=\"color:#6E7448\"> ~/.bashrc</span><span style=\"color:#8B8676;font-style:italic\">            # carrega o nvm no shell atual</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> use</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">node</span><span style=\"color:#6E7448\"> --version</span><span style=\"color:#8B8676;font-style:italic\">              # deve imprimir v24.x</span></span></code></pre>\n<p>Com o Ubuntu configurado e o Node 24 ativo, você está pronto para instalar o Open Design.</p>\n<h2 id=\"step-2--install-open-design\">Passo 2 — Instalar o Open Design</h2>\n<h3 id=\"option-a--windows-desktop-app-recommended-zero-config\">Opção A — App de desktop do Windows (recomendado, zero configuração)</h3>\n<p>Acesse <a href=\"https://open-design.ai/\">open-design.ai</a> e clique em <strong>Download desktop</strong>. Existe uma versão nativa para <strong>Windows (x64)</strong> (além das de macOS e Linux). Execute o instalador, abra o app e ele detecta automaticamente todas as CLIs de agentes de programação que já estão no seu <code>PATH</code>, depois carrega para você as skills e os design systems integrados. Sem WSL, sem terminal — este é o caminho mais simples no Windows.</p>\n<h3 id=\"option-b--run-from-source-inside-wsl\">Opção B — Rodar a partir do código-fonte (dentro do WSL)</h3>\n<p>Este é o caminho que o AI Automation demonstra. Trabalhando dentro do seu shell do Ubuntu com o Node 24 ativo, clone o repositório e inicie o runtime web:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>O <code>corepack enable</code> permite que o Corepack selecione a versão do pnpm fixada no repositório (<code>10.33.x</code>), de modo que você não instala o pnpm por conta própria. O <code>pnpm install</code> baixa as dependências e compila as partes nativas — isso pode levar alguns minutos na primeira execução, o que é esperado, não uma falha. O <code>pnpm tools-dev run web</code> então inicia o daemon local e o servidor web.</p>\n<p>Quando termina, o comando <strong>imprime uma URL local</strong> — copie-a e cole-a no seu <strong>navegador do Windows</strong>. O WSL encaminha a porta para o Windows automaticamente, então o app simplesmente abre.</p>\n<blockquote>\n<p><strong>Importante:</strong> a porta é <strong>atribuída dinamicamente</strong> na inicialização — leia o endereço real que o comando imprime. Não presuma uma porta fixa; o endereço pode variar na sua máquina e entre execuções.</p>\n</blockquote>\n<h3 id=\"option-c--install-into-your-coding-agent-wsl\">Opção C — Instalar no seu agente de programação (WSL)</h3>\n<p>Prefere pular a interface gráfica e chamar o Open Design como um servidor MCP dentro do seu agente? No WSL há <strong>um passo extra primeiro</strong>. O Linux já vem com o <code>/usr/bin/od</code> (a ferramenta de octal-dump), que sobrepõe o próprio <code>od</code> do Open Design — então o <code>od mcp install …</code> falharia, do contrário, com «file not found» para <code>mcp</code>/<code>install</code>. Adicione um pequeno wrapper que aponte o <code>od</code> para o seu clone e coloque-o primeiro no <code>PATH</code>:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">mkdir</span><span style=\"color:#6E7448\"> -p</span><span style=\"color:#6E7448\"> ~/.local/bin</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cat</span><span style=\"color:#ED6F5C\"> ></span><span style=\"color:#6E7448\"> ~/.local/bin/od</span><span style=\"color:#ED6F5C\"> &#x3C;&#x3C;</span><span style=\"color:#5A5448\">'EOF'</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">#!/usr/bin/env bash</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">repo=\"$HOME/open-design\"     # o clone ~/open-design da Opção B</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">cd \"$repo\" || exit 127</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">exec corepack pnpm exec od \"$@\"</span></span>\n<span class=\"line\"><span style=\"color:#5A5448\">EOF</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">chmod</span><span style=\"color:#6E7448\"> +x</span><span style=\"color:#6E7448\"> ~/.local/bin/od</span></span>\n<span class=\"line\"><span style=\"color:#ED6F5C\">export</span><span style=\"color:#2A2620\"> PATH</span><span style=\"color:#ED6F5C\">=</span><span style=\"color:#5A5448\">\"</span><span style=\"color:#2A2620\">$HOME</span><span style=\"color:#6E7448\">/.local/bin:</span><span style=\"color:#2A2620\">$PATH</span><span style=\"color:#5A5448\">\"</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">hash</span><span style=\"color:#6E7448\"> -r</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">type</span><span style=\"color:#6E7448\"> -a</span><span style=\"color:#6E7448\"> od</span><span style=\"color:#8B8676;font-style:italic\">                   # agora o od do Open Design deve vencer</span></span></code></pre>\n<p>Depois, integre-o ao seu agente:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">od</span><span style=\"color:#6E7448\"> mcp</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> &#x3C;</span><span style=\"color:#6E7448\">agen</span><span style=\"color:#15140F\">t</span><span style=\"color:#ED6F5C\">></span></span>\n<span class=\"line\"><span style=\"color:#8B8676;font-style:italic\"># &#x3C;agent> = claude | codex | cursor | copilot | gemini | opencode | …</span></span></code></pre>\n<p>Depois, dentro do agente, basta pedir: <code>Use open-design to generate a landing page with the Airbnb design system</code>.</p>\n<h2 id=\"first-run-connect-your-coding-agent\">Primeira execução: conecte seu agente de programação</h2>\n<p>Na primeira vez que o espaço de trabalho carrega, o Open Design varre seu ambiente e mostra todas as CLIs que encontrou. Como o WSL é uma máquina Linux de verdade, ele detecta os agentes instalados <strong>dentro do Ubuntu</strong> — então uma CLI do Gemini ou outro agente que viva no WSL é detectado ali. Clique em <strong>rescan</strong> se algo ainda não aparecer.</p>\n<ul>\n<li><strong>Escolha um agente e um modelo padrão.</strong> Deixe a CLI instalada conduzir a geração, ou aponte-a para um provedor e modelo específicos. Como o vídeo enfatiza, um modelo mais forte significa um resultado visivelmente melhor, então recorra a um modelo capaz quando o resultado importar.</li>\n<li><strong>Adicione provedores de mídia (opcional).</strong> Para gerar imagens, vídeo ou áudio, cole suas próprias chaves de API — traga sua própria chave, apenas para os provedores que você realmente usa.</li>\n<li><strong>Conecte serviços MCP (opcional).</strong> Integre conectores se quiser que o agente busque dados de outras fontes.</li>\n<li><strong>Defina suas preferências.</strong> Idioma, aparência, notificações — até um pet de desktop. Você pode mudar tudo isso depois, então mantenha a primeira passada simples.</li>\n</ul>\n<h2 id=\"explore-the-workspace\">Explore o espaço de trabalho</h2>\n<p>O Open Design mantém seu trabalho <strong>delimitado por projeto</strong>: quando você o executa sobre uma pasta, os designs que cria ficam dentro do diretório daquele projeto. Sua primeira lista de projetos estará vazia — isso é normal.</p>\n<p>Dentro de um projeto você pode criar protótipos, apresentações de slides, imagens, vídeos e mais. Dois pontos de partida fazem a tela em branco desaparecer:</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/02-design-systems.webp\" alt=\"A biblioteca integrada de design systems.\">\n<em>A biblioteca de design systems: escolha o visual de uma marca real — Airbnb, Airtable e muitas outras — e o Open Design leva seus tokens, cores e tipografia para o seu design.</em></p>\n<ul>\n<li>Os <strong>design systems</strong> capturam o visual de uma marca como um <code>DESIGN.md</code> de tokens — cores primárias e secundárias, tipografia, espaçamento. Visualize um e você poderá construir diretamente sobre ele em vez de definir uma paleta do zero.</li>\n<li>Os <strong>templates</strong> abrangem protótipos, slides e geração tanto de imagem quanto de vídeo. Filtre por tipo e faça um fork de qualquer um para começar com vantagem.</li>\n</ul>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/03-templates.webp\" alt=\"A biblioteca de templates.\">\n<em>Templates: pontos de partida para protótipo, slide, imagem e vídeo — filtre por tipo e faça um fork para começar.</em></p>\n<p>Você pode explorar a biblioteca completa na web em <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> antes de instalar qualquer coisa.</p>\n<h2 id=\"build-something\">Crie algo</h2>\n<p>Aqui está o fluxo que o AI Automation executa, reescrito para a versão atual:</p>\n<ol>\n<li><strong>Escolha um design system.</strong> Escolha um de que você goste — digamos <strong>Airbnb</strong> — e abra-o para inspecionar seu <code>DESIGN.md</code> e seus tokens.</li>\n<li><strong>Importe-o como ponto de partida.</strong> Use <strong>Share → Download as ZIP</strong> e, em seguida, no seu projeto, escolha <strong>Import flat design ZIP</strong>. O design aparece no espaço de trabalho, pronto para construir sobre ele.</li>\n<li><strong>Descreva a mudança que você quer.</strong> Digite um briefing em linguagem natural — <em>«Você pode deixar o fundo escuro?»</em> — e envie. O agente lê o design system, planeja seu trabalho e produz uma nova versão do artefato.</li>\n<li><strong>Itere à vontade.</strong> Mude fontes, adicione ou remova um logotipo, faça upload dos seus próprios recursos e deixe que sejam posicionados nos lugares certos. Cada prompt produz uma nova proposta para manter ou descartar.</li>\n<li><strong>Exporte quando estiver satisfeito.</strong> Clique em <strong>Share</strong> e baixe o resultado como um ZIP.</li>\n</ol>\n<p>O resultado é um design real e editável conduzido pelo modelo que você conectou — então um agente capaz se traduz diretamente naquilo que você recebe de volta.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Dicas para extrair mais do produto</h2>\n<ul>\n<li><strong>Escolha um modelo forte.</strong> A qualidade do resultado acompanha o agente que você conecta — um modelo gratuito serve para aprender o fluxo, mas um modelo capaz vale a pena para o trabalho de verdade.</li>\n<li><strong>Leia a URL impressa toda vez.</strong> O endereço local é dinâmico; copie o que o <code>tools-dev</code> imprime em vez de reutilizar um link antigo.</li>\n<li><strong>Instale seus agentes onde o Open Design vai procurar.</strong> Rodando a partir do código-fonte no WSL? Instale suas CLIs dentro do Ubuntu para que o espaço de trabalho as detecte; o app de desktop lê o seu <code>PATH</code> do Windows.</li>\n<li><strong>Você não precisa de um design system para começar.</strong> Comece a partir de um integrado, importe um ZIP ou deixe o Open Design inferir os padrões. Seus designs ficam com a pasta do projeto, então organize o trabalho executando-o sobre o diretório certo.</li>\n</ul>\n<h2 id=\"faq\">Perguntas frequentes</h2>\n<p><strong>O Open Design é gratuito?</strong>\nSim — é de código aberto sob a licença Apache-2.0. Você pode rodá-lo localmente de graça; você só paga pelo uso do modelo/API de qualquer agente e provedores de mídia que conectar.</p>\n<p><strong>Devo usar o WSL ou o app de desktop do Windows?</strong>\nPara a maioria das pessoas, a versão de desktop nativa do Windows (x64) é mais simples — sem WSL, sem Node, sem clonar nada. Use o caminho a partir do código-fonte via WSL quando quiser especificamente ler ou modificar o código. Observe que o WSL2 é um caminho suportado de forma primária, enquanto o nativo do Windows é de melhor esforço; se você encontrar atrito com um, tente o outro.</p>\n<p><strong>Quais agentes de programação ele suporta?</strong>\nMais de 21 agentes, incluindo Claude Code, Codex, Cursor, Gemini, GitHub Copilot e OpenCode. O Open Design detecta as CLIs já instaladas na sua máquina — dentro do WSL para o caminho a partir do código-fonte, ou no seu <code>PATH</code> do Windows para o app de desktop.</p>\n<p><strong>Como ele se diferencia do Claude Design?</strong>\nA mesma sensação familiar, mas de código aberto, local-first e plugável a agentes — então você não fica preso a um único modelo nem queima um pool fixo de créditos. Ele também vai além dos protótipos, com apresentações de slides, layouts no estilo revista, geração de imagens e vídeo.</p>\n<hr>\n<p><em>Este guia escrito é baseado no tutorial de instalação no Windows do AI Automation. Assista ao vídeo completo acima e <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">inscreva-se no canal do AI Automation</a> para mais vídeos práticos sobre ferramentas de IA.</em></p>",
  },
  "it": {
    title: "ADDIO Claude Design! Questo è il MIGLIOR generatore di UI con IA open source",
    summary: "Installa ed esegui Open Design su Windows 11 — la semplice build desktop nativa, più il percorso da sorgente tramite WSL con Node 24 e pnpm. Esegui localmente il generatore di UI con IA open source, senza abbonamenti cloud. Basato sulla guida di AI Automation.",
    bodyHtml: "<p>Questa guida è pensata per gli utenti Windows che vogliono eseguire Open Design sulla propria macchina — niente account cloud, nessun credito mensile da consumare. Segue il percorso adottato da AI Automation nella <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">loro guida all'installazione su Windows</a>, riscritta e aggiornata alla versione attuale così da poterla seguire comando per comando. Guarda il video qui sopra per la dimostrazione dal vivo, oppure prosegui con la versione scritta.</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/01-workspace.webp\" alt=\"Lo spazio di lavoro di Open Design in esecuzione locale.\">\n<em>Open Design in esecuzione locale su Windows: uno spazio di lavoro di design open source e agent-native sotto il tuo pieno controllo.</em></p>\n<h2 id=\"what-is-open-design\">Cos'è Open Design?</h2>\n<p>Open Design è una piattaforma di design open source e local-first — un'alternativa agent-native a Claude Design e Figma. Invece di vincolarti a un singolo fornitore di modelli, gira <strong>sopra l'agente di programmazione che già usi</strong>: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode e una dozzina di altri. È “porta il tuo agente” più che semplicemente porta la tua chiave.</p>\n<p>Alcuni motivi per cui vale la pena dargli un'occhiata:</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — clonalo, ospitalo in autonomia, leggi ogni riga.</li>\n<li><strong>Gira localmente</strong> — i tuoi progetti vivono nelle tue cartelle sulla tua macchina, non nel cloud di qualcun altro.</li>\n<li><strong>Agente intercambiabile</strong> — sono supportati oltre 21 agenti di programmazione; scegli tu quale CLI guida la generazione, e la qualità del risultato segue il modello che selezioni.</li>\n<li><strong>Più dei semplici prototipi</strong> — prototipi, artefatti dal vivo, presentazioni, layout in stile rivista, generazione di immagini e perfino video, tutto da un unico spazio di lavoro.</li>\n<li><strong>Una libreria integrata di design system e template</strong>, così non parti da una tela bianca.</li>\n</ul>\n<p>Se hai usato Claude Design, la sensazione ti sarà subito familiare — Open Design mantiene la stessa estetica pacata, poi vi aggiunge funzionalità (e la tua scelta del modello).</p>\n<h2 id=\"before-you-start\">Prima di iniziare</h2>\n<p>Hai tre modi per installare Open Design su Windows. Scegli quello che fa per te:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Percorso</th><th>Ideale per</th><th>Requisiti</th></tr></thead><tbody><tr><td><strong>App desktop (Windows x64)</strong></td><td>La maggior parte degli utenti Windows — zero configurazione</td><td>Nessuno. Scarica e apri.</td></tr><tr><td><strong>Esecuzione da sorgente (WSL)</strong></td><td>Sviluppatori che vogliono leggere o modificare il codice</td><td>WSL2 + Ubuntu, Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Installazione nel tuo agente</strong></td><td>Chi vive nel terminale</td><td>Una CLI di un agente di programmazione già esistente</td></tr></tbody></table>\n<p>Il video usa il percorso da sorgente tramite WSL, ottimo se vuoi muoverti dentro il repository. Ma per la maggior parte delle persone la <strong>build desktop nativa per Windows è il percorso consigliato</strong> — esiste un installer per Windows (x64) che non richiede WSL, né Node, né clonazione. Questa guida copre entrambi; la procedura WSL qui sotto è per quando vuoi specificamente il percorso da sorgente.</p>\n<h2 id=\"step-1--set-up-wsl\">Passo 1 — Configura WSL</h2>\n<p>Se vuoi solo l'app desktop, salta al Passo 2, Opzione A. Se vuoi il percorso da sorgente, ti serve prima un ambiente Linux dentro Windows. È esattamente ciò che fornisce WSL (Windows Subsystem for Linux) — una vera shell Ubuntu in esecuzione affiancata a Windows, senza dual-boot e senza macchine virtuali da gestire.</p>\n<p><strong>1. Installa WSL e Ubuntu.</strong> Apri PowerShell ed esegui <code>wsl --install</code> — questo abilita WSL2 e installa Ubuntu per impostazione predefinita. Riavvia se Windows lo richiede, poi avvia <strong>Ubuntu</strong> dal menu Start e imposta il tuo nome utente e password Linux alla prima apertura. (Hai già Ubuntu da un altro strumento? Riutilizzalo — non c'è bisogno di ripetere questa operazione.)</p>\n<p><strong>2. Aggiorna i pacchetti di base.</strong> Dentro la shell Ubuntu, aggiorna l'indice dei pacchetti e installa l'essenziale:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> update</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#6E7448\"> -y</span><span style=\"color:#6E7448\"> curl</span><span style=\"color:#6E7448\"> git</span></span></code></pre>\n<blockquote>\n<p><strong>Suggerimento per la risoluzione dei problemi dal video:</strong> se un passaggio successivo genera uno strano errore, riavvia in modo pulito la tua istanza Linux — da PowerShell esegui <code>wsl --shutdown</code>, poi riapri Ubuntu. Un riavvio da zero risolve la maggior parte degli intoppi al primo avvio.</p>\n</blockquote>\n<p><strong>3. Installa Node 24.</strong> La build da sorgente punta a Node <code>~24</code>. Una Ubuntu pulita non ha ancora <code>nvm</code>, quindi installalo prima, poi usalo per ottenere Node 24:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">curl</span><span style=\"color:#6E7448\"> -o-</span><span style=\"color:#6E7448\"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.3/install.sh</span><span style=\"color:#ED6F5C\"> |</span><span style=\"color:#15140F;font-weight:bold\"> bash</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">source</span><span style=\"color:#6E7448\"> ~/.bashrc</span><span style=\"color:#8B8676;font-style:italic\">            # carica nvm nella shell corrente</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> use</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">node</span><span style=\"color:#6E7448\"> --version</span><span style=\"color:#8B8676;font-style:italic\">              # dovrebbe stampare v24.x</span></span></code></pre>\n<p>Con Ubuntu configurato e Node 24 attivo, sei pronto a installare Open Design.</p>\n<h2 id=\"step-2--install-open-design\">Passo 2 — Installa Open Design</h2>\n<h3 id=\"option-a--windows-desktop-app-recommended-zero-config\">Opzione A — App desktop per Windows (consigliata, zero configurazione)</h3>\n<p>Vai su <a href=\"https://open-design.ai/\">open-design.ai</a> e fai clic su <strong>Download desktop</strong>. Esiste una build nativa per <strong>Windows (x64)</strong> (insieme a macOS e Linux). Esegui l'installer, apri l'app e questa rileva automaticamente ogni CLI di agente di programmazione già presente nel tuo <code>PATH</code>, poi carica per te le skill integrate e i design system. Niente WSL, niente terminale — è il percorso più semplice su Windows.</p>\n<h3 id=\"option-b--run-from-source-inside-wsl\">Opzione B — Esecuzione da sorgente (dentro WSL)</h3>\n<p>Questo è il percorso che dimostra AI Automation. Lavorando dentro la tua shell Ubuntu con Node 24 attivo, clona il repository e avvia il runtime web:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p><code>corepack enable</code> consente a Corepack di selezionare la versione di pnpm fissata nel repository (<code>10.33.x</code>), così non devi installare pnpm da solo. <code>pnpm install</code> scarica le dipendenze e compila le parti native — al primo avvio può richiedere un paio di minuti, il che è previsto, non un errore. <code>pnpm tools-dev run web</code> avvia poi il daemon locale e il server web.</p>\n<p>Quando finisce, il comando <strong>stampa un URL locale</strong> — copialo e incollalo nel tuo <strong>browser Windows</strong>. WSL inoltra automaticamente la porta verso Windows, così l'app si apre senza problemi.</p>\n<blockquote>\n<p><strong>Importante:</strong> la porta viene <strong>assegnata dinamicamente</strong> all'avvio — leggi l'indirizzo effettivo che il comando stampa. Non dare per scontata una porta fissa; l'indirizzo può variare sulla tua macchina e tra un'esecuzione e l'altra.</p>\n</blockquote>\n<h3 id=\"option-c--install-into-your-coding-agent-wsl\">Opzione C — Installazione nel tuo agente di programmazione (WSL)</h3>\n<p>Preferisci saltare la GUI e richiamare Open Design come server MCP dentro il tuo agente? Su WSL c'è <strong>prima un passaggio extra</strong>. Linux include già <code>/usr/bin/od</code> (lo strumento octal-dump), che oscura l'<code>od</code> di Open Design — quindi <code>od mcp install …</code> fallirebbe altrimenti con “file not found” per <code>mcp</code>/<code>install</code>. Aggiungi un piccolo wrapper che punta <code>od</code> al tuo clone e mettilo per primo nel <code>PATH</code>:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">mkdir</span><span style=\"color:#6E7448\"> -p</span><span style=\"color:#6E7448\"> ~/.local/bin</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cat</span><span style=\"color:#ED6F5C\"> ></span><span style=\"color:#6E7448\"> ~/.local/bin/od</span><span style=\"color:#ED6F5C\"> &#x3C;&#x3C;</span><span style=\"color:#5A5448\">'EOF'</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">#!/usr/bin/env bash</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">repo=\"$HOME/open-design\"     # il clone ~/open-design dell'Opzione B</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">cd \"$repo\" || exit 127</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">exec corepack pnpm exec od \"$@\"</span></span>\n<span class=\"line\"><span style=\"color:#5A5448\">EOF</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">chmod</span><span style=\"color:#6E7448\"> +x</span><span style=\"color:#6E7448\"> ~/.local/bin/od</span></span>\n<span class=\"line\"><span style=\"color:#ED6F5C\">export</span><span style=\"color:#2A2620\"> PATH</span><span style=\"color:#ED6F5C\">=</span><span style=\"color:#5A5448\">\"</span><span style=\"color:#2A2620\">$HOME</span><span style=\"color:#6E7448\">/.local/bin:</span><span style=\"color:#2A2620\">$PATH</span><span style=\"color:#5A5448\">\"</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">hash</span><span style=\"color:#6E7448\"> -r</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">type</span><span style=\"color:#6E7448\"> -a</span><span style=\"color:#6E7448\"> od</span><span style=\"color:#8B8676;font-style:italic\">                   # ora dovrebbe vincere l'od di Open Design</span></span></code></pre>\n<p>Poi collegalo al tuo agente:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">od</span><span style=\"color:#6E7448\"> mcp</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> &#x3C;</span><span style=\"color:#6E7448\">agen</span><span style=\"color:#15140F\">t</span><span style=\"color:#ED6F5C\">></span></span>\n<span class=\"line\"><span style=\"color:#8B8676;font-style:italic\"># &#x3C;agent> = claude | codex | cursor | copilot | gemini | opencode | …</span></span></code></pre>\n<p>Poi, dentro l'agente, basta chiedere: <code>Use open-design to generate a landing page with the Airbnb design system</code>.</p>\n<h2 id=\"first-run-connect-your-coding-agent\">Primo avvio: collega il tuo agente di programmazione</h2>\n<p>La prima volta che lo spazio di lavoro si carica, Open Design analizza il tuo ambiente e mostra ogni CLI trovata. Poiché WSL è una vera macchina Linux, rileva gli agenti installati <strong>dentro Ubuntu</strong> — quindi una CLI Gemini o un altro agente che vive in WSL viene individuato lì. Fai clic su <strong>rescan</strong> se qualcosa non compare ancora.</p>\n<ul>\n<li><strong>Scegli un agente e un modello predefiniti.</strong> Lascia che la CLI installata guidi la generazione, oppure puntala su un fornitore e un modello specifici. Come sottolinea il video, un modello più potente significa un risultato sensibilmente migliore, quindi affidati a uno capace quando il risultato conta.</li>\n<li><strong>Aggiungi fornitori di media (facoltativo).</strong> Per generare immagini, video o audio, incolla le tue chiavi API — bring-your-own-key, solo per i fornitori che usi davvero.</li>\n<li><strong>Collega i servizi MCP (facoltativo).</strong> Collega i connettori se vuoi che l'agente attinga ad altre fonti.</li>\n<li><strong>Imposta le preferenze.</strong> Lingua, aspetto, notifiche — perfino un pet sul desktop. Puoi modificare tutto questo in seguito, quindi al primo giro mantieni la semplicità.</li>\n</ul>\n<h2 id=\"explore-the-workspace\">Esplora lo spazio di lavoro</h2>\n<p>Open Design mantiene il tuo lavoro <strong>circoscritto al progetto</strong>: quando lo esegui su una cartella, i design che crei vivono dentro la directory di quel progetto. Il tuo primo elenco di progetti sarà vuoto — è normale.</p>\n<p>Dentro un progetto puoi creare prototipi, presentazioni, immagini, video e altro. Due punti di partenza fanno sparire la tela bianca:</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/02-design-systems.webp\" alt=\"La libreria integrata di design system.\">\n<em>La libreria di design system: scegli un vero look di brand — Airbnb, Airtable e molti altri — e Open Design porta i suoi token, colori e tipografia nel tuo design.</em></p>\n<ul>\n<li>I <strong>design system</strong> catturano il look di un brand come un <code>DESIGN.md</code> di token — colori primari e secondari, tipografia, spaziatura. Vedine l'anteprima e puoi costruirci direttamente sopra invece di definire una palette da zero.</li>\n<li>I <strong>template</strong> coprono prototipi, presentazioni e generazione sia di immagini sia di video. Filtra per tipo e fai il fork di uno qualsiasi come punto di partenza.</li>\n</ul>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/03-templates.webp\" alt=\"La libreria dei template.\">\n<em>Template: punti di partenza per prototipo, presentazione, immagine e video — filtra per tipo e fai il fork per iniziare.</em></p>\n<p>Puoi sfogliare l'intera libreria sul web su <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> prima di installare qualsiasi cosa.</p>\n<h2 id=\"build-something\">Crea qualcosa</h2>\n<p>Ecco il flusso che esegue AI Automation, riscritto per la versione attuale:</p>\n<ol>\n<li><strong>Scegli un design system.</strong> Scegline uno che ti piace — diciamo <strong>Airbnb</strong> — e aprilo per esaminarne il <code>DESIGN.md</code> e i token.</li>\n<li><strong>Importalo come punto di partenza.</strong> Usa <strong>Share → Download as ZIP</strong>, poi nel tuo progetto scegli <strong>Import flat design ZIP</strong>. Il design compare nello spazio di lavoro, pronto su cui costruire.</li>\n<li><strong>Indica la modifica che vuoi.</strong> Scrivi un brief in linguaggio naturale — <em>“Puoi rendere lo sfondo scuro?”</em> — e invialo. L'agente legge il design system, pianifica il lavoro e produce una nuova versione dell'artefatto.</li>\n<li><strong>Itera liberamente.</strong> Cambia i font, aggiungi o rimuovi un logo, carica i tuoi asset e falli posizionare nei punti giusti. Ogni prompt produce una nuova interpretazione da tenere o scartare.</li>\n<li><strong>Esporta quando sei soddisfatto.</strong> Premi <strong>Share</strong> e scarica il risultato come ZIP.</li>\n</ol>\n<p>Il risultato è un design reale e modificabile guidato dal modello che hai collegato — quindi un agente capace ripaga direttamente in ciò che ottieni.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Consigli per sfruttarlo al meglio</h2>\n<ul>\n<li><strong>Scegli un modello potente.</strong> La qualità del risultato segue l'agente che colleghi — un modello gratuito va bene per imparare il flusso, ma per il lavoro vero vale la pena usarne uno capace.</li>\n<li><strong>Leggi ogni volta l'URL stampato.</strong> L'indirizzo locale è dinamico; copia ciò che <code>tools-dev</code> stampa invece di riutilizzare un vecchio link.</li>\n<li><strong>Installa i tuoi agenti dove Open Design cercherà.</strong> Esegui da sorgente in WSL? Installa le tue CLI dentro Ubuntu così lo spazio di lavoro le rileva; l'app desktop legge il tuo <code>PATH</code> di Windows.</li>\n<li><strong>Non ti serve un design system per iniziare.</strong> Parti da uno integrato, importa uno ZIP o lascia che Open Design deduca i valori predefiniti. I tuoi design restano con la cartella del progetto, quindi organizza il lavoro eseguendolo sulla directory giusta.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Open Design è gratuito?</strong>\nSì — è open source sotto licenza Apache-2.0. Puoi eseguirlo localmente gratis; paghi solo per l'uso del modello/API di qualunque agente e fornitore di media colleghi.</p>\n<p><strong>Dovrei usare WSL o l'app desktop per Windows?</strong>\nPer la maggior parte delle persone, la build desktop nativa per Windows (x64) è più semplice — niente WSL, niente Node, niente clonazione. Usa il percorso da sorgente WSL quando vuoi specificamente leggere o modificare il codice. Nota che WSL2 è un percorso supportato in via primaria, mentre Windows-native è best-effort; se incontri attriti con uno, prova l'altro.</p>\n<p><strong>Quali agenti di programmazione supporta?</strong>\nOltre 21 agenti, inclusi Claude Code, Codex, Cursor, Gemini, GitHub Copilot e OpenCode. Open Design rileva le CLI già installate sulla tua macchina — dentro WSL per il percorso da sorgente, o sul tuo <code>PATH</code> di Windows per l'app desktop.</p>\n<p><strong>In cosa è diverso da Claude Design?</strong>\nStessa sensazione familiare, ma open source, local-first e con agente intercambiabile — quindi non sei vincolato a un solo modello né consumi un pool di crediti fisso. Va anche oltre i prototipi con presentazioni, layout in stile rivista, generazione di immagini e video.</p>\n<hr>\n<p><em>Questa guida scritta è basata sulla guida all'installazione su Windows di AI Automation. Guarda il video completo qui sopra e <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">iscriviti ad AI Automation</a> per altri video pratici sugli strumenti di IA.</em></p>",
  },
  "tr": {
    title: "Hoşça kal Claude Design! İşte EN İYİ açık kaynaklı yapay zekâ arayüz üreticisi",
    summary: "Open Design'ı Windows 11'de kurun ve çalıştırın — basit, yerel masaüstü sürümü ile Node 24 ve pnpm kullanarak WSL üzerinden kaynaktan derleme yolu. Açık kaynaklı yapay zekâ arayüz üreticisini yerelde çalıştırın, bulut aboneliği olmadan. AI Automation'ın anlatımına dayanmaktadır.",
    bodyHtml: "<p>Bu kılavuz, Open Design'ı kendi makinesinde çalıştırmak isteyen Windows kullanıcıları içindir — bulut hesabı yok, tüketilecek aylık kredi yok. AI Automation'ın <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">Windows kurulum anlatımında</a> izlediği yolu takip eder; mevcut sürüme göre yeniden yazılıp güncellenmiştir, böylece komut komut adım adım ilerleyebilirsiniz. Canlı çalışma için yukarıdaki videoyu izleyin ya da yazılı sürüm için okumaya devam edin.</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/01-workspace.webp\" alt=\"Yerelde çalışan Open Design çalışma alanı.\">\n<em>Windows'ta yerelde çalışan Open Design: tamamen sizin kontrolünüzdeki, açık kaynaklı, agent-native bir tasarım çalışma alanı.</em></p>\n<h2 id=\"what-is-open-design\">Open Design nedir?</h2>\n<p>Open Design, açık kaynaklı ve yerel öncelikli bir tasarım platformudur — Claude Design ve Figma'ya agent-native bir alternatif. Sizi tek bir model sağlayıcısına kilitlemek yerine, <strong>zaten kullandığınız kodlama ajanının üzerinde</strong> çalışır: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode ve bir düzine daha fazlası. Bu, yalnızca \"kendi anahtarını getir\" değil, \"kendi ajanını getir\" yaklaşımıdır.</p>\n<p>Göz atmaya değer kılan birkaç şey:</p>\n<ul>\n<li><strong>Açık kaynak, Apache-2.0</strong> — klonlayın, kendi sunucunuzda barındırın, her satırı okuyun.</li>\n<li><strong>Yerelde çalışır</strong> — projeleriniz başkasının bulutunda değil, kendi makinenizdeki kendi klasörlerinizde yaşar.</li>\n<li><strong>Ajan takılabilir</strong> — 21'den fazla kodlama ajanı desteklenir; üretimi hangi CLI'nin yöneteceğini siz seçersiniz ve çıktının kalitesi seçtiğiniz modele göre değişir.</li>\n<li><strong>Prototiplerden fazlası</strong> — prototipler, canlı yapıtlar, slayt destpleri, dergi düzenleri, görsel üretimi ve hatta video; hepsi tek bir çalışma alanından.</li>\n<li><strong>Yerleşik bir tasarım sistemleri ve şablonlar kütüphanesi</strong>, böylece boş bir tuvalden başlamazsınız.</li>\n</ul>\n<p>Claude Design kullandıysanız, his anında tanıdık gelecek — Open Design aynı sakin estetiği korur, ardından bunun üzerine yetenekler (ve model seçiminizi) ekler.</p>\n<h2 id=\"before-you-start\">Başlamadan önce</h2>\n<p>Open Design'ı Windows'a kurmanın üç yolu var. Size uyanı seçin:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Yol</th><th>Kimler için en iyisi</th><th>Gereksinimler</th></tr></thead><tbody><tr><td><strong>Masaüstü uygulaması (Windows x64)</strong></td><td>Çoğu Windows kullanıcısı — sıfır yapılandırma</td><td>Yok. İndir ve aç.</td></tr><tr><td><strong>Kaynaktan çalıştır (WSL)</strong></td><td>Kodu okumak veya değiştirmek isteyen geliştiriciler</td><td>WSL2 + Ubuntu, Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Ajanınıza kur</strong></td><td>Terminalde yaşayanlar</td><td>Mevcut bir kodlama ajanı CLI'si</td></tr></tbody></table>\n<p>Video, kaynaktan WSL yolunu kullanıyor; bu, deponun içinde yaşamak istiyorsanız harikadır. Ancak çoğu kişi için <strong>önerilen yol yerel Windows masaüstü sürümüdür</strong> — WSL, Node veya klonlama gerektirmeyen bir Windows (x64) yükleyicisi vardır. Bu kılavuz her ikisini de kapsar; aşağıdaki WSL anlatımı, özellikle kaynak yolunu istediğiniz durumlar içindir.</p>\n<h2 id=\"step-1--set-up-wsl\">Adım 1 — WSL'yi kurun</h2>\n<p>Yalnızca masaüstü uygulamasını istiyorsanız, Adım 2, Seçenek A'ya geçin. Kaynaktan yolu istiyorsanız, önce Windows içinde bir Linux ortamına ihtiyacınız var. WSL'nin (Windows Subsystem for Linux) sunduğu tam olarak budur — Windows'un yanında çalışan gerçek bir Ubuntu kabuğu; çift önyükleme yok, dadılık edilecek sanal makine yok.</p>\n<p><strong>1. WSL ve Ubuntu'yu kurun.</strong> PowerShell'i açın ve <code>wsl --install</code> komutunu çalıştırın — bu, WSL2'yi etkinleştirir ve varsayılan olarak Ubuntu'yu kurar. Windows isterse yeniden başlatın, ardından Başlat menüsünden <strong>Ubuntu</strong>'yu başlatın ve ilk açılışında Linux kullanıcı adınızı ve parolanızı belirleyin. (Başka bir araçtan zaten Ubuntu'nuz mu var? Onu yeniden kullanın — bunu tekrarlamaya gerek yok.)</p>\n<p><strong>2. Temel paketleri güncelleyin.</strong> Ubuntu kabuğunun içinde, paket dizinini yenileyin ve gerekli olanları kurun:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> update</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> sudo</span><span style=\"color:#6E7448\"> apt</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#6E7448\"> -y</span><span style=\"color:#6E7448\"> curl</span><span style=\"color:#6E7448\"> git</span></span></code></pre>\n<blockquote>\n<p><strong>Videodan sorun giderme ipucu:</strong> sonraki bir adım garip bir hata verirse, Linux örneğinizi temiz bir şekilde yeniden başlatın — PowerShell'den <code>wsl --shutdown</code> komutunu çalıştırın, ardından Ubuntu'yu yeniden açın. Yeni bir başlangıç, çoğu ilk çalıştırma aksaklığını giderir.</p>\n</blockquote>\n<p><strong>3. Node 24'ü kurun.</strong> Kaynaktan derleme Node <code>~24</code>'ü hedefler. Temiz bir Ubuntu'da henüz <code>nvm</code> yoktur, bu yüzden önce onu kurun, ardından Node 24'ü almak için kullanın:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">curl</span><span style=\"color:#6E7448\"> -o-</span><span style=\"color:#6E7448\"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.3/install.sh</span><span style=\"color:#ED6F5C\"> |</span><span style=\"color:#15140F;font-weight:bold\"> bash</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">source</span><span style=\"color:#6E7448\"> ~/.bashrc</span><span style=\"color:#8B8676;font-style:italic\">            # nvm'yi mevcut kabuğa yükle</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">nvm</span><span style=\"color:#6E7448\"> use</span><span style=\"color:#ED6F5C\"> 24</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">node</span><span style=\"color:#6E7448\"> --version</span><span style=\"color:#8B8676;font-style:italic\">              # v24.x yazdırmalı</span></span></code></pre>\n<p>Ubuntu kurulu ve Node 24 etkinken, Open Design'ı kurmaya hazırsınız.</p>\n<h2 id=\"step-2--install-open-design\">Adım 2 — Open Design'ı kurun</h2>\n<h3 id=\"option-a--windows-desktop-app-recommended-zero-config\">Seçenek A — Windows masaüstü uygulaması (önerilir, sıfır yapılandırma)</h3>\n<p><a href=\"https://open-design.ai/\">open-design.ai</a> adresine gidin ve <strong>Download desktop</strong>'a tıklayın. (macOS ve Linux'un yanı sıra) yerel bir <strong>Windows (x64)</strong> sürümü vardır. Yükleyiciyi çalıştırın, uygulamayı açın; <code>PATH</code>'inizde zaten bulunan her kodlama ajanı CLI'sini otomatik olarak algılar, ardından yerleşik becerileri ve tasarım sistemlerini sizin için yükler. WSL yok, terminal yok — bu, Windows'taki en basit yoldur.</p>\n<h3 id=\"option-b--run-from-source-inside-wsl\">Seçenek B — Kaynaktan çalıştır (WSL içinde)</h3>\n<p>Bu, AI Automation'ın gösterdiği yoldur. Node 24 etkin Ubuntu kabuğunuzun içinde çalışarak, depoyu klonlayın ve web çalışma zamanını başlatın:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> ~/open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p><code>corepack enable</code>, Corepack'in depoda sabitlenmiş pnpm sürümünü (<code>10.33.x</code>) seçmesini sağlar, böylece pnpm'i kendiniz kurmazsınız. <code>pnpm install</code> bağımlılıkları çeker ve yerel parçaları derler — ilk çalıştırmada bu birkaç dakika sürebilir, bu beklenen bir durumdur, hata değildir. Ardından <code>pnpm tools-dev run web</code>, yerel arka plan hizmetini ve web sunucusunu başlatır.</p>\n<p>Bittiğinde, komut <strong>yerel bir URL yazdırır</strong> — onu kopyalayın ve <strong>Windows tarayıcınıza</strong> yapıştırın. WSL, bağlantı noktasını otomatik olarak Windows'a iletir, böylece uygulama doğrudan açılır.</p>\n<blockquote>\n<p><strong>Önemli:</strong> bağlantı noktası başlangıçta <strong>dinamik olarak atanır</strong> — komutun yazdırdığı gerçek adresi okuyun. Sabit bir bağlantı noktası varsaymayın; adres makinenize göre ve çalıştırmalar arasında farklılık gösterebilir.</p>\n</blockquote>\n<h3 id=\"option-c--install-into-your-coding-agent-wsl\">Seçenek C — Kodlama ajanınıza kurun (WSL)</h3>\n<p>GUI'yi atlamayı ve Open Design'ı ajanınızın içinde bir MCP sunucusu olarak çağırmayı mı tercih ediyorsunuz? WSL'de önce <strong>fazladan bir adım</strong> vardır. Linux, Open Design'ın kendi <code>od</code>'sini gölgeleyen <code>/usr/bin/od</code> (sekizlik döküm aracı) ile zaten gelir — bu yüzden aksi takdirde <code>od mcp install …</code>, <code>mcp</code>/<code>install</code> için \"file not found\" hatasıyla başarısız olurdu. <code>od</code>'yi klonunuza yönlendiren küçük bir sarmalayıcı ekleyin ve onu <code>PATH</code>'te ilk sıraya koyun:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">mkdir</span><span style=\"color:#6E7448\"> -p</span><span style=\"color:#6E7448\"> ~/.local/bin</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cat</span><span style=\"color:#ED6F5C\"> ></span><span style=\"color:#6E7448\"> ~/.local/bin/od</span><span style=\"color:#ED6F5C\"> &#x3C;&#x3C;</span><span style=\"color:#5A5448\">'EOF'</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">#!/usr/bin/env bash</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">repo=\"$HOME/open-design\"     # the ~/open-design clone from Option B</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">cd \"$repo\" || exit 127</span></span>\n<span class=\"line\"><span style=\"color:#6E7448\">exec corepack pnpm exec od \"$@\"</span></span>\n<span class=\"line\"><span style=\"color:#5A5448\">EOF</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">chmod</span><span style=\"color:#6E7448\"> +x</span><span style=\"color:#6E7448\"> ~/.local/bin/od</span></span>\n<span class=\"line\"><span style=\"color:#ED6F5C\">export</span><span style=\"color:#2A2620\"> PATH</span><span style=\"color:#ED6F5C\">=</span><span style=\"color:#5A5448\">\"</span><span style=\"color:#2A2620\">$HOME</span><span style=\"color:#6E7448\">/.local/bin:</span><span style=\"color:#2A2620\">$PATH</span><span style=\"color:#5A5448\">\"</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">hash</span><span style=\"color:#6E7448\"> -r</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">type</span><span style=\"color:#6E7448\"> -a</span><span style=\"color:#6E7448\"> od</span><span style=\"color:#8B8676;font-style:italic\">                   # artık Open Design'ın od'si kazanmalı</span></span></code></pre>\n<p>Ardından bunu ajanınıza bağlayın:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">od</span><span style=\"color:#6E7448\"> mcp</span><span style=\"color:#6E7448\"> install</span><span style=\"color:#ED6F5C\"> &#x3C;</span><span style=\"color:#6E7448\">agen</span><span style=\"color:#15140F\">t</span><span style=\"color:#ED6F5C\">></span></span>\n<span class=\"line\"><span style=\"color:#8B8676;font-style:italic\"># &#x3C;agent> = claude | codex | cursor | copilot | gemini | opencode | …</span></span></code></pre>\n<p>Sonra, ajanın içinde yalnızca şunu isteyin: <code>Use open-design to generate a landing page with the Airbnb design system</code>.</p>\n<h2 id=\"first-run-connect-your-coding-agent\">İlk çalıştırma: kodlama ajanınızı bağlayın</h2>\n<p>Çalışma alanı ilk kez yüklendiğinde, Open Design ortamınızı tarar ve bulduğu her CLI'yi gösterir. WSL gerçek bir Linux makinesi olduğundan, <strong>Ubuntu içine</strong> kurulu ajanları da yakalar — yani WSL'de yaşayan bir Gemini CLI veya başka bir ajan orada algılanır. Henüz görünmeyen bir şey varsa <strong>rescan</strong> (yeniden tara) seçeneğine tıklayın.</p>\n<ul>\n<li><strong>Varsayılan bir ajan ve model seçin.</strong> Üretimi kurulu CLI'ye bırakın ya da belirli bir sağlayıcıya ve modele yönlendirin. Videonun vurguladığı gibi, daha güçlü bir model gözle görülür şekilde daha iyi çıktı demektir, bu yüzden sonuç önemli olduğunda yetenekli olanı tercih edin.</li>\n<li><strong>Medya sağlayıcıları ekleyin (isteğe bağlı).</strong> Görsel, video veya ses üretmek için kendi API anahtarlarınızı yapıştırın — kendi anahtarını getir, yalnızca gerçekten kullandığınız sağlayıcılar için.</li>\n<li><strong>MCP hizmetlerini bağlayın (isteğe bağlı).</strong> Ajanın başka kaynaklardan veri çekmesini istiyorsanız bağlayıcıları devreye sokun.</li>\n<li><strong>Tercihleri ayarlayın.</strong> Dil, görünüm, bildirimler — hatta bir masaüstü evcil hayvanı. Bunların hepsini daha sonra değiştirebilirsiniz, bu yüzden ilk geçişi basit tutun.</li>\n</ul>\n<h2 id=\"explore-the-workspace\">Çalışma alanını keşfedin</h2>\n<p>Open Design işinizi <strong>proje kapsamında</strong> tutar: onu bir klasöre karşı çalıştırdığınızda, oluşturduğunuz tasarımlar o proje dizininin içinde yaşar. İlk proje listeniz boş olacak — bu normaldir.</p>\n<p>Bir projenin içinde prototipler, slayt destpleri, görseller, videolar ve daha fazlasını oluşturabilirsiniz. İki başlangıç noktası, boş tuvali ortadan kaldırır:</p>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/02-design-systems.webp\" alt=\"Yerleşik tasarım sistemleri kütüphanesi.\">\n<em>Tasarım sistemleri kütüphanesi: gerçek bir marka görünümü seçin — Airbnb, Airtable ve daha pek çoğu — ve Open Design onun token'larını, renklerini ve tipografisini tasarımınıza taşısın.</em></p>\n<ul>\n<li><strong>Tasarım sistemleri</strong>, bir markanın görünümünü token'lardan oluşan bir <code>DESIGN.md</code> olarak yakalar — birincil ve ikincil renkler, tipografi, boşluklar. Birini önizleyin, bir paleti sıfırdan tanımlamak yerine doğrudan onun üzerine inşa edebilirsiniz.</li>\n<li><strong>Şablonlar</strong>, prototipleri, slaytları ve hem görsel hem video üretimini kapsar. Türe göre filtreleyin ve bir adım önde başlamak için herhangi birini fork'layın.</li>\n</ul>\n<p><img src=\"/tutorials/open-design-windows-wsl-installation-setup-ai-automation/03-templates.webp\" alt=\"Şablonlar kütüphanesi.\">\n<em>Şablonlar: prototip, slayt, görsel ve video başlangıç noktaları — türe göre filtreleyin ve başlamak için fork'layın.</em></p>\n<p>Herhangi bir şey kurmadan önce, kütüphanenin tamamına web üzerinde <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> adresinden göz atabilirsiniz.</p>\n<h2 id=\"build-something\">Bir şeyler oluşturun</h2>\n<p>İşte AI Automation'ın izlediği akış, mevcut sürüm için yeniden yazılmış hali:</p>\n<ol>\n<li><strong>Bir tasarım sistemi seçin.</strong> Beğendiğiniz birini seçin — diyelim <strong>Airbnb</strong> — ve <code>DESIGN.md</code> ile token'larını incelemek için açın.</li>\n<li><strong>Başlangıç noktası olarak içe aktarın.</strong> <strong>Share → Download as ZIP</strong>'i kullanın, ardından projenizde <strong>Import flat design ZIP</strong>'i seçin. Tasarım çalışma alanında belirir ve üzerine inşa etmeye hazırdır.</li>\n<li><strong>İstediğiniz değişikliği yazın.</strong> Sade bir dille bir özet girin — <em>\"Arka planı koyu yapabilir misin?\"</em> — ve gönderin. Ajan tasarım sistemini okur, işini planlar ve yapıtın yeni bir sürümünü üretir.</li>\n<li><strong>Özgürce yineleyin.</strong> Yazı tiplerini değiştirin, bir logo ekleyin veya kaldırın, kendi varlıklarınızı yükleyip doğru yerlere yerleştirilmelerini sağlayın. Her istek, saklayacağınız ya da atacağınız taze bir yorum üretir.</li>\n<li><strong>Memnun kaldığınızda dışa aktarın.</strong> <strong>Share</strong>'e basın ve sonucu ZIP olarak indirin.</li>\n</ol>\n<p>Çıktı, bağladığınız modelin yönlendirdiği gerçek, düzenlenebilir bir tasarımdır — yani yetenekli bir ajan, geri aldığınızda doğrudan kendini gösterir.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Daha fazlasını elde etmek için ipuçları</h2>\n<ul>\n<li><strong>Güçlü bir model seçin.</strong> Çıktı kalitesi bağladığınız ajana göre değişir — akışı öğrenmek için ücretsiz bir model işe yarar, ama gerçek iş için yetenekli olan buna değer.</li>\n<li><strong>Her seferinde yazdırılan URL'yi okuyun.</strong> Yerel adres dinamiktir; eski bir bağlantıyı yeniden kullanmak yerine <code>tools-dev</code>'in yazdırdığını kopyalayın.</li>\n<li><strong>Ajanlarınızı Open Design'ın bakacağı yere kurun.</strong> WSL'de kaynaktan mı çalıştırıyorsunuz? CLI'lerinizi Ubuntu içine kurun ki çalışma alanı onları algılasın; masaüstü uygulaması ise Windows <code>PATH</code>'inizi okur.</li>\n<li><strong>Başlamak için bir tasarım sistemine ihtiyacınız yok.</strong> Yerleşik bir tanesinden başlayın, bir ZIP içe aktarın veya Open Design'ın varsayılanları çıkarsamasına izin verin. Tasarımlarınız proje klasörüyle birlikte kalır, bu yüzden işi doğru dizine karşı çalıştırarak düzenleyin.</li>\n</ul>\n<h2 id=\"faq\">SSS</h2>\n<p><strong>Open Design ücretsiz mi?</strong>\nEvet — Apache-2.0 lisansı altında açık kaynaktır. Onu yerelde ücretsiz çalıştırabilirsiniz; yalnızca bağladığınız ajanın ve medya sağlayıcılarının model/API kullanımı için ödeme yaparsınız.</p>\n<p><strong>WSL'yi mi yoksa Windows masaüstü uygulamasını mı kullanmalıyım?</strong>\nÇoğu kişi için yerel Windows (x64) masaüstü sürümü daha basittir — WSL yok, Node yok, klonlama yok. Kodu özellikle okumak veya değiştirmek istediğinizde kaynaktan WSL yolunu kullanın. WSL2'nin birincil desteklenen yol olduğunu, Windows-yerel sürümün ise elden geldiğince desteklendiğini unutmayın; biriyle zorlanırsanız diğerini deneyin.</p>\n<p><strong>Hangi kodlama ajanlarını destekliyor?</strong>\nClaude Code, Codex, Cursor, Gemini, GitHub Copilot ve OpenCode dahil 21'den fazla ajan. Open Design, makinenizde zaten kurulu olan CLI'leri algılar — kaynak yolu için WSL içinde ya da masaüstü uygulaması için Windows <code>PATH</code>'inizde.</p>\n<p><strong>Claude Design'dan farkı ne?</strong>\nAynı tanıdık his, ama açık kaynaklı, yerel öncelikli ve ajan takılabilir — yani tek bir modele kilitlenmez veya sabit bir kredi havuzunu tüketmezsiniz. Ayrıca prototiplerin ötesine geçer: slayt destpleri, dergi düzenleri, görsel üretimi ve video.</p>\n<hr>\n<p><em>Bu yazılı kılavuz, AI Automation'ın Windows kurulum anlatımına dayanmaktadır. Yukarıdaki tam videoyu izleyin ve daha fazla uygulamalı yapay zekâ aracı videosu için <a href=\"https://www.youtube.com/watch?v=GjPYMNsb9mo\">AI Automation'a abone olun</a>.</em></p>",
  },
};
